INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('MATH-G1-NS-SCO1', 'MATH-G1-NS-ELO1', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Count with meaning to 20 by building quantities; and matching quantity with numeral.', 1, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO2', 'MATH-G1-NS-ELO1', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Orally sequence numbers to 100 by 1s, 2s, 5s and 10s.', 2, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO3', 'MATH-G1-NS-ELO1', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Count backwards from  20 by 1s, 2s, 5s and 10s.', 3, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO4', 'MATH-G1-NS-ELO1', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Count backwards from 100 by 5s and 10s.', 4, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO5', 'MATH-G1-NS-ELO1', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Identify error/s in a counting sequence up to 20. ', 5, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO6', 'MATH-G1-NS-ELO1', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Use Number lines (vertical and horizontal) and number charts to support counting and skip counting. ', 6, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO7', 'MATH-G1-NS-ELO1', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Counts by 2s, and 5 to find a total in multiplicative contexts (repetitive addition).  ', 7, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO8', 'MATH-G1-NS-ELO1', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Quantify sets up to 20 and state that the last number said is the amount counted. ', 8, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO9', 'MATH-G1-NS-ELO1', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Identify numeral for quantities and vice versa.', 9, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO10', 'MATH-G1-NS-ELO2', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Represent a given number up to 20 using a variety of concrete models, including ten- frames and created materials. ', 10, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO11', 'MATH-G1-NS-ELO2', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Model a given number up to 20 using a variety of pictorial representation. ', 11, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO12', 'MATH-G1-NS-ELO2', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Find examples of a given number in the environment. ', 12, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO13', 'MATH-G1-NS-ELO2', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Place given numerals on a number line (vertical and horizontal) with benchmarks 0, 5, 10, 15 and 20. ', 13, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO14', 'MATH-G1-NS-ELO2', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Partition any given quantity up to 20 into two parts and identify the number of objects in each part. ', 14, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO15', 'MATH-G1-NS-ELO2', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Model a given number using two different objects.', 15, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO16', 'MATH-G1-NS-ELO2', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Subitize for quantities 1-10. ', 16, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO17', 'MATH-G1-NS-ELO3', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Build sets and set models to show how numbers compare  ', 17, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO18', 'MATH-G1-NS-ELO3', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Explain which set has more and which set has fewer. ', 18, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO19', 'MATH-G1-NS-ELO3', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Build a set that has fewer or more than a given set up to 20 ', 19, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO20', 'MATH-G1-NS-ELO3', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Build a set that is between two given sets. ', 20, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO21', 'MATH-G1-NS-ELO3', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Use ordinal language (first, second, third……)', 21, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO22', 'MATH-G1-NS-ELO3', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Discuss the importance of the number 10. ', 22, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO23', 'MATH-G1-NS-ELO3', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Explain that teens numbers are represented as 10 and more.  ', 23, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO24', 'MATH-G1-NS-ELO3', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Use models such as ten frames to show numbers up to 20 as 10 and some more.  ', 24, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO25', 'MATH-G1-NS-ELO4', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Count teen numbers using familiar numbers. ', 25, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO26', 'MATH-G1-NS-ELO4', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Model teen numbers up to 20 in a variety of ways using sets of tens and ones.', 26, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO27', 'MATH-G1-NS-ELO4', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Recognize that in a teen number, the 1 represents one group of ten. ', 27, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO28', 'MATH-G1-NS-ELO4', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Explain that teen numbers are composed of one ten and one, two, three, four, five, six, seven, eight, or nine ones. ', 28, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-NS-SCO29', 'MATH-G1-NS-ELO4', 'MATH-G1-NS', 'MATH', 'mathematics', 'G1', '1', 'Number Sense', 'Compose and decompose numbers from 11 to 19 into tens and ones. ', 29, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-ON-SCO1', 'MATH-G1-ON-ELO1', 'MATH-G1-ON', 'MATH', 'mathematics', 'G1', '1', 'Operations with Numbers', 'Combine quantities (sets, lengths, etc.) using concrete materials to get the total or find a missing value up to 20. ', 30, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-ON-SCO2', 'MATH-G1-ON-ELO1', 'MATH-G1-ON', 'MATH', 'mathematics', 'G1', '1', 'Operations with Numbers', 'Partition and recombine quantities to relate to addition and subtraction. ', 31, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-ON-SCO3', 'MATH-G1-ON-ELO1', 'MATH-G1-ON', 'MATH', 'mathematics', 'G1', '1', 'Operations with Numbers', 'Explain how addition and subtraction are related.', 32, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-ON-SCO4', 'MATH-G1-ON-ELO1', 'MATH-G1-ON', 'MATH', 'mathematics', 'G1', '1', 'Operations with Numbers', 'Add and subtract within 20, using a variety of strategies.  ', 33, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-ON-SCO5', 'MATH-G1-ON-ELO1', 'MATH-G1-ON', 'MATH', 'mathematics', 'G1', '1', 'Operations with Numbers', 'Determine if equations involving addition and subtraction are true.  ', 34, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-ON-SCO6', 'MATH-G1-ON-ELO1', 'MATH-G1-ON', 'MATH', 'mathematics', 'G1', '1', 'Operations with Numbers', 'Separate quantities to find a missing value from a number up to 20. ', 35, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-ON-SCO7', 'MATH-G1-ON-ELO1', 'MATH-G1-ON', 'MATH', 'mathematics', 'G1', '1', 'Operations with Numbers', 'Comparing two quantities to find the difference from a number up to 20', 36, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-ON-SCO8', 'MATH-G1-ON-ELO2', 'MATH-G1-ON', 'MATH', 'mathematics', 'G1', '1', 'Operations with Numbers', 'Using symbols for addition (+) and subtraction (-) as a way to record calculations done through stories, building, and drawing. ', 37, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-ON-SCO9', 'MATH-G1-ON-ELO2', 'MATH-G1-ON', 'MATH', 'mathematics', 'G1', '1', 'Operations with Numbers', 'Make reasonable estimation when combining, separating, comparing & partitioning quantities to 20.', 38, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-ON-SCO10', 'MATH-G1-ON-ELO3', 'MATH-G1-ON', 'MATH', 'mathematics', 'G1', '1', 'Operations with Numbers', 'Model and describe equal collections of objects as ___ groups of ___. ', 39, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-ON-SCO11', 'MATH-G1-ON-ELO3', 'MATH-G1-ON', 'MATH', 'mathematics', 'G1', '1', 'Operations with Numbers', 'Form equal groups of objects and use repeated addition to represent the group. ', 40, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-ON-SCO12', 'MATH-G1-ON-ELO3', 'MATH-G1-ON', 'MATH', 'mathematics', 'G1', '1', 'Operations with Numbers', 'Skip count to find the total number of objects in groups. ', 41, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-ON-SCO13', 'MATH-G1-ON-ELO3', 'MATH-G1-ON', 'MATH', 'mathematics', 'G1', '1', 'Operations with Numbers', 'Write mathematical statements to represent groups of equal objects.  ', 42, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-ON-SCO14', 'MATH-G1-ON-ELO3', 'MATH-G1-ON', 'MATH', 'mathematics', 'G1', '1', 'Operations with Numbers', 'Share objects into equal groups and state how many objects are in each group. ', 43, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-ON-SCO15', 'MATH-G1-ON-ELO3', 'MATH-G1-ON', 'MATH', 'mathematics', 'G1', '1', 'Operations with Numbers', 'Write mathematical statements to represent equal groups of objects shared.  ', 44, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-PR-SCO1', 'MATH-G1-PR-ELO1', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'Describe, copy and extend a repeating pattern with 2 to 4 elements (using manipulatives, diagrams, body movements/actions/sounds) ', 45, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-PR-SCO2', 'MATH-G1-PR-ELO1', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'Translate a repeating pattern from one representation or modality to another (E.g., a repeating orientation pattern to a repeating sound pattern, etc.)  ', 46, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-PR-SCO3', 'MATH-G1-PR-ELO1', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'Spot and correct errors in a repeating pattern. ', 47, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-PR-SCO4', 'MATH-G1-PR-ELO1', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'Identify and describe repeating patterns in the environment (both man-made and nature) ', 48, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-PR-SCO5', 'MATH-G1-PR-ELO1', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'Show appreciation for their peers’ creation of patterns and patterns in our environment by identifying and describing the pattern observed. around them ', 49, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-PR-SCO6', 'MATH-G1-PR-ELO1', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'Identify and enjoy patterns in poems, stories, (folk and modern) within their culture.  ', 50, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('MATH-G1-PR-SCO7', 'MATH-G1-PR-ELO2', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'Interpret, describe and extend a given increasing and decreasing pattern that grows by 1 or 2 each time with no more than 4 elements in the core. ', 51, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-PR-SCO8', 'MATH-G1-PR-ELO2', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'Use a variety of tools and models to create, generate and interpret patterns that increase or decrease by 1 or 2 each time (blocks, pattern strips, pattern blocks, etc.) ', 52, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-PR-SCO9', 'MATH-G1-PR-ELO2', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'Identify missing elements and/or errors in a given increasing and decreasing pattern. ', 53, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-PR-SCO10', 'MATH-G1-PR-ELO2', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'Show an appreciation for patterns found in the environment around them by recognizing, talking about, describing and recreating their own examples based on observations.', 54, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-PR-SCO11', 'MATH-G1-PR-ELO3', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'Identify and describe missing quantities in numbers up to 20 by using a variety of concrete materials to represent situations. ', 55, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-PR-SCO12', 'MATH-G1-PR-ELO3', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'represent missing quantities in numbers up to 20 by writing number sentences in semantic and computational forms: - using joining, separating, part - part whole and comparing structures/ relationships ,  - using the inverse of the given operation ', 56, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-PR-SCO13', 'MATH-G1-PR-ELO4', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'Use different number combinations and linear models to create equivalent number values and lengths up to a total of 20. ', 57, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-PR-SCO14', 'MATH-G1-PR-ELO4', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'Identify and use equivalent relationships of equal length, number and number sentences adding up to 20.', 58, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-PR-SCO15', 'MATH-G1-PR-ELO4', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'Compare lengths, number, and number sentences using the equal sign.', 59, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-PR-SCO16', 'MATH-G1-PR-ELO5', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'Determine whether given pairs of expressions are equivalence or balance using concrete objects, as well as operations on whole numbers. ', 60, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-PR-SCO17', 'MATH-G1-PR-ELO5', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'Interpret the meaning of the equal sign correctly and determine if equations involving addition and subtraction are true or false.  ', 61, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-PR-SCO18', 'MATH-G1-PR-ELO5', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'Determine the unknown whole number in an addition or subtraction equation with three whole numbers.  ', 62, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-PR-SCO19', 'MATH-G1-PR-ELO5', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'Formulate number sentences to solve word problems (including real-life scenarios/situations) involving addition of two or three whole numbers and subtraction of two whole numbers. ', 63, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-PR-SCO20', 'MATH-G1-PR-ELO5', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'Express equalities as different representations of the same quantity (0 to 20). ', 64, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-PR-SCO21', 'MATH-G1-PR-ELO5', 'MATH-G1-PR', 'MATH', 'mathematics', 'G1', '1', 'Patterns and Relationships', 'Use addition and subtraction up to 20 to solve one step word problems involving adding to, taking from, putting together and taking apart, with unknowns in all positions.  ', 65, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO1', 'MATH-G1-GT-ELO1', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Use language that describes 3D objects, such as cube, cone, cylinder, sphere, orally and in writing to describe a picture or object in realworld contexts. ', 66, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO2', 'MATH-G1-GT-ELO1', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Use language that describes polygons, such as square, rectangle, and triangle, orally and in writing to describe a picture or object in real-world contexts. ', 67, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO3', 'MATH-G1-GT-ELO1', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Recognize and name 3D shapes. ', 68, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO4', 'MATH-G1-GT-ELO1', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Recognize and name 2D shapes.  ', 69, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO5', 'MATH-G1-GT-ELO1', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Identify 2D shapes in real world context. ', 70, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO6', 'MATH-G1-GT-ELO1', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Identify 3D shapes in real world context. ', 71, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO7', 'MATH-G1-GT-ELO1', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Identify and name the 2D and 3D shapes whenever they undergo transformation.', 72, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO8', 'MATH-G1-GT-ELO2', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Recognize and name the basic 2D shapes (circle, square, rectangle, and triangle) and 3D objects (cube, cone, sphere, and cylinder).', 73, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G2-DH-SCO12', 'MATH-G2-DH-ELO3', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Collect, group and analyze data.  ', 713, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G1-GT-SCO9', 'MATH-G1-GT-ELO2', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Represent and construct the basic 2D shapes and 3D objects using appropriate materials and tools. ', 74, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO10', 'MATH-G1-GT-ELO2', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Justify the properties of the basic 2D shapes and 3D objects, such as the number of sides, corners, and faces. ', 75, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO11', 'MATH-G1-GT-ELO2', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Replicate and construct composite 2D shapes by combining the basic shapes in different ways. ', 76, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO12', 'MATH-G1-GT-ELO2', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Replicate and construct 3D objects by combining the basic 3D objects in different ways. ', 77, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO13', 'MATH-G1-GT-ELO2', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Compare the characteristics of shapes and objects, such as the number of sides, corners, and faces, and identify similarities and differences between them. ', 78, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO14', 'MATH-G1-GT-ELO2', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Sort and pattern shapes and objects based on their characteristics, such as the number of sides, corners, and faces, and create patterns using different shapes and colors. ', 79, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO15', 'MATH-G1-GT-ELO2', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Represent and construct the basic 2D shapes and 3D objects using appropriate materials and tools. ', 80, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO16', 'MATH-G1-GT-ELO2', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Replicate and construct 3D objects by combining the basic 3D objects in different ways.', 81, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO17', 'MATH-G1-GT-ELO2', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Discuss the importance of geometrical shapes in the environment. ', 82, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO18', 'MATH-G1-GT-ELO2', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Students will volunteer to role play scenarios involving geometry shapes to show their  appreciation for Geometry.  ', 83, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO19', 'MATH-G1-GT-ELO3', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Identify and name 2D shapes and 3D objects, including cubes, cones, cylinders, spheres, squares, rectangles, triangles, and circles. ', 84, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO20', 'MATH-G1-GT-ELO3', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Describe the attributes of 2D shapes, including the number of sides and corners, and whether the sides are straight or curved. ', 85, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO21', 'MATH-G1-GT-ELO3', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Describe the attributes of 3D objects, including the number of corners, whether they have flat or curved sides, and whether they are uniform in thickness or come to a point. ', 86, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO22', 'MATH-G1-GT-ELO3', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Compare and contrast the attributes of different 3D objects, such as noting that a sphere has no corners or flat sides, while a cube has six square faces and eight corners. ', 87, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO23', 'MATH-G1-GT-ELO3', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Create and extend patterns using 2D shapes, including squares, rectangles, triangles, and circles. ', 88, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO24', 'MATH-G1-GT-ELO3', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Sort and classify 2D shapes and 3D objects based on their attributes, such as sorting by the number of sides or corners. ', 89, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO25', 'MATH-G1-GT-ELO3', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Use appropriate vocabulary to describe 2D shapes and 3D objects, such as using the terms "corner" and "vertex" interchangeably or describing a cylinder as having a curved surface and two circular bases.', 90, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO26', 'MATH-G1-GT-ELO4', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Identify and name 2D shapes: Students should be able to recognize and name basic 2D shapes such as squares, rectangles, circles, triangles, and hexagons. ', 91, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO27', 'MATH-G1-GT-ELO4', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Identify and name 3D objects: Students should be able to recognize and name basic 3D objects such as cubes, cones, cylinders, and spheres. ', 92, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO28', 'MATH-G1-GT-ELO4', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Apply knowledge of 2D and 3D shapes in practical contexts, such as solving problems involving shape and space, with support appropriate to their individual needs. ', 93, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO29', 'MATH-G1-GT-ELO4', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Sort 2D shapes based on their attributes, such as the number of sides, the length of sides, and the number of angles. ', 94, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO30', 'MATH-G1-GT-ELO4', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Sort 3D objects based on their attributes, such as the number of faces, edges, and vertices. ', 95, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO31', 'MATH-G1-GT-ELO4', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Compare and contrast 2D shapes and 3D objects identifying similarities and differences between 2D shapes and 3D objects, such as the number of dimensions and the presence of faces, edges, and vertices. ', 96, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO32', 'MATH-G1-GT-ELO4', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Create 2D shapes and 3D objects using various materials, such as paper, clay, and blocks. ', 97, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO33', 'MATH-G1-GT-ELO4', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Use mathematical vocabulary related to shapes, such as vertices, edges, faces, and symmetry. ', 98, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO34', 'MATH-G1-GT-ELO4', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Identify and describe realworld objects that are 2D shapes or 3D objects, such as circles on a clock face or a cone-shaped ice cream cone. ', 99, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('MATH-G1-GT-SCO35', 'MATH-G1-GT-ELO4', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Solve basic geometric problems involving 2D shapes and 3D objects, such as counting the number of faces on a cube or sorting 2D shapes based on their attributes.', 100, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO36', 'MATH-G1-GT-ELO5', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Identify the basic shapes, such as circle, square, rectangle, and triangle. ', 101, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO37', 'MATH-G1-GT-ELO5', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Create and explore with different materials such as playdough, blocks, foam to form different shapes. ', 102, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO38', 'MATH-G1-GT-ELO5', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Find shapes in the environment such as in buildings, signs, or everyday objects.  ', 103, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO39', 'MATH-G1-GT-ELO5', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Sort shapes based on their attributes.  ', 104, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO40', 'MATH-G1-GT-ELO5', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Identify and create patterns using geometric shapes.  ', 105, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO41', 'MATH-G1-GT-ELO6', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Construct composite objects using different shapes ', 106, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO42', 'MATH-G1-GT-ELO6', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Identify the different shapes used in the composite objects created. ', 107, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO43', 'MATH-G1-GT-ELO6', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'State the characteristics of the shapes that make them easy or difficult to build with.  ', 108, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO44', 'MATH-G1-GT-ELO6', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Discuss and describe the composite objects.  ', 109, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO45', 'MATH-G1-GT-ELO6', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Compare and contrast different composite objects.  ', 110, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO46', 'MATH-G1-GT-ELO7', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Identify and name at least three different 2D shapes (e.g., circles, squares, rectangles, triangles) that can be found in cubes, cones, cylinders, and spheres. ', 111, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO47', 'MATH-G1-GT-ELO7', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Create and name 2D shapes by using physical objects (such as cubes, cones, cylinders, and spheres) to create "footprints" or "shadows" on paper.', 112, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO48', 'MATH-G1-GT-ELO7', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Describe the resulting cross-section of slicing a cube, cone, cylinder, or sphere is sliced, the resulting cross-sections can be different 2D shapes, and be able to identify and name these shapes. ', 113, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO49', 'MATH-G1-GT-ELO7', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Use appropriate vocabulary (e.g., edges, vertices, sides, circles, triangles) to describe the features of cubes, cones, cylinders, and spheres, and explain how these features can be used to identify the 2D shapes within them. ', 114, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO50', 'MATH-G1-GT-ELO7', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Apply knowledge of 2D shapes to real-world objects by identifying and naming the 2D shapes that can be found in everyday objects that resemble cubes, cones, cylinders, and spheres, such as a soccer ball (sphere) or a building block (cube). ', 115, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO51', 'MATH-G1-GT-ELO8', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Identify and name common 3D shapes, such as cubes, spheres, cones, and cylinders. ', 116, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO52', 'MATH-G1-GT-ELO8', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Use basic spatial concepts, such as up, down, in front of, behind, and beside correctly. ', 117, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO53', 'MATH-G1-GT-ELO8', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Use concrete materials, such as playdough, sand, or clay, to create 3D shapes and objects. ', 118, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO54', 'MATH-G1-GT-ELO8', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Transform 3D objects by molding, shaping, stretching, and flattening the materials. ', 119, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO55', 'MATH-G1-GT-ELO8', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Identify similarities and differences between transformed and original objects. ', 120, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO56', 'MATH-G1-GT-ELO8', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Use mathematical language to describe the transformations, such as "flattened," "stretched," or "twisted." ', 121, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO57', 'MATH-G1-GT-ELO8', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Explore different ways to transform objects, such as rotating, flipping, or sliding. ', 122, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO58', 'MATH-G1-GT-ELO8', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Use trial and error to solve problems related to transforming objects. ', 123, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO59', 'MATH-G1-GT-ELO8', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Work collaboratively with peers to create and transform 3D objects. ', 124, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-GT-SCO60', 'MATH-G1-GT-ELO8', 'MATH-G1-GT', 'MATH', 'mathematics', 'G1', '1', 'Geometrical Thinking', 'Reflect on learning and identify areas for improvement in their ability to transform 3D objects.', 125, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO1', 'MATH-G1-M-ELO1', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Explore physical materials and describe them using the vocabulary associated with linear measure (short/long, high/low, near/far, thick/thin, narrow/wide, deep/shallow). ', 126, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO2', 'MATH-G1-M-ELO1', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Classify the measuring attribute of length based on the vocabulary associated with it. ', 127, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO3', 'MATH-G1-M-ELO1', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Explore physical materials and describe them using the vocabulary associated with capacity (full, empty, same as). ', 128, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO4', 'MATH-G1-M-ELO1', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Categorise the measuring attribute of capacity based on the vocabulary associated with it. ', 129, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO5', 'MATH-G1-M-ELO1', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Explore physical materials and describe them using the vocabulary associated with mass of an object (heavy/light). ', 130, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO6', 'MATH-G1-M-ELO1', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Categorise the measuring attribute of mass based on the vocabulary associated with it. ', 131, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO7', 'MATH-G1-M-ELO1', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Explore physical materials and describe them using the vocabulary associated with area of a surface of an object (large/small). ', 132, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO8', 'MATH-G1-M-ELO1', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Categorise the measuring attribute of area based on the vocabulary associated with it. ', 133, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO9', 'MATH-G1-M-ELO2', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Compare the length of two objects using direct comparison (i.e: place side by side and align one end) and explain reasoning using appropriate vocabulary; (shorter/longer, higher/lower, deeper/shallower, nearer/farther, thinner/ thicker, wider and narrower). ', 134, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO10', 'MATH-G1-M-ELO2', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Compare the mass of two objects (lifting, pushing,  pulling and balancing) and explain reasoning using appropriate vocabulary;  ', 135, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO11', 'MATH-G1-M-ELO2', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Compare the capacity of two objects (filling and emptying) and explain reasoning using appropriate vocabulary (such as more or less, level is higher than or less than).   . ', 136, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO12', 'MATH-G1-M-ELO2', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Compare the area of two objects using direct comparison(i.e which one occupies more space) and explain reasoning using appropriate vocabulary (such as bigger and smaller).  ', 137, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO13', 'MATH-G1-M-ELO3', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Measure length, mass and capacity using non standard units ', 138, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO14', 'MATH-G1-M-ELO3', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Select appropriate non standard units to measure different attributes. ', 139, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO15', 'MATH-G1-M-ELO3', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Compare the capacity of two containers to determine which holds more. ', 140, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO16', 'MATH-G1-M-ELO3', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Use parts of their body to conduct nonstandard measurement. (Palms, hand span, foot span) ', 141, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO17', 'MATH-G1-M-ELO3', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Use objects to conduct non-standard measurement. (little stones, blocks, sand, toy cars, paper clips etc.) ', 142, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO18', 'MATH-G1-M-ELO3', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Estimate and measure the mass and length of objects using non-standard measurement. ', 143, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO19', 'MATH-G1-M-ELO3', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Apply the correct non-standard measurement to measure various items. Example: You would not use a hand span to measure capacity.  ', 144, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO20', 'MATH-G1-M-ELO3', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Show enthusiasm using non-standard measurement to measure objects. ', 145, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO21', 'MATH-G1-M-ELO3', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'List examples when they estimate measurement in their everyday lives. ', 146, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO22', 'MATH-G1-M-ELO3', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Appreciate the importance of using estimations in everyday situations.  ', 147, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO23', 'MATH-G1-M-ELO4', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'State the days of the week, months of the year and holidays. ', 148, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO24', 'MATH-G1-M-ELO4', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Explain the composition of days for week, weeks for month and months for year. ', 149, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
