  ('MATH-G1-M-SCO26', 'MATH-G1-M-ELO4', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Identify 5c, 10c and 25c and relate their value to pennies (1c) ', 151, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO27', 'MATH-G1-M-ELO4', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Read the date on the calendar. ', 152, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO28', 'MATH-G1-M-ELO4', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Interpret details on a calendar. ', 153, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO29', 'MATH-G1-M-ELO4', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Represent and recognize time on the hour and half past the hour on the analog and digital clock. ', 154, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO30', 'MATH-G1-M-ELO4', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'State their birthdate with pride.', 155, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-M-SCO31', 'MATH-G1-M-ELO4', 'MATH-G1-M', 'MATH', 'mathematics', 'G1', '1', 'Measurement', 'Be willing to share the date every morning in class.', 156, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO1', 'MATH-G1-DH-ELO1', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Construct simple questions based on observation. ', 157, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO2', 'MATH-G1-DH-ELO1', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'State the information that can be collected by using a given question.', 158, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO3', 'MATH-G1-DH-ELO1', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Identify sources for collecting information for data. ', 159, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO4', 'MATH-G1-DH-ELO1', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Formulate questions that can be addressed with data collected to answer them  ', 160, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO5', 'MATH-G1-DH-ELO1', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Observe objects/ people in the environment. ', 161, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO6', 'MATH-G1-DH-ELO1', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Communicate with others and among peers regarding their observations. ', 162, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO7', 'MATH-G1-DH-ELO1', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Count the number of objects/ people based on observation. ', 163, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO8', 'MATH-G1-DH-ELO1', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Justify reasons for answers ', 164, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO9', 'MATH-G1-DH-ELO1', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Make connections with numbers  ', 165, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO10', 'MATH-G1-DH-ELO1', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Willingly participate in observation activities. ', 166, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO11', 'MATH-G1-DH-ELO1', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Learn to appreciate that questions that are worded differently can obtain the same answer.', 167, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO12', 'MATH-G1-DH-ELO1', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Accept that information can come from multiple sources.', 168, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO13', 'MATH-G1-DH-ELO2', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Sort objects/ people according to one attribute (shape, colour, size, properties, ethnicity, occupation, etc.) ', 169, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO14', 'MATH-G1-DH-ELO2', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Represent the information collected from observations /experiments/ interviews in multiple ways. ', 170, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO15', 'MATH-G1-DH-ELO2', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Use a variety of different methods (counting, matching, grouping, rearranging, ordering, using counters, etc.) to collect and sort data.   ', 171, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO16', 'MATH-G1-DH-ELO2', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Collect data in different ways to answer questions. ', 172, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO17', 'MATH-G1-DH-ELO2', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Use symbols/tables/groupings to sort and organise data collected. ', 173, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO18', 'MATH-G1-DH-ELO2', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Appreciate the fact that different information can be derived from objects sorted. ', 174, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO19', 'MATH-G1-DH-ELO2', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Show willingness to collect, organise and display data', 175, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO20', 'MATH-G1-DH-ELO3', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Explain how and why a given data set can be arranged in different orders. ', 176, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO21', 'MATH-G1-DH-ELO3', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'State the highest and least value in each data set. ', 177, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO22', 'MATH-G1-DH-ELO3', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Compare the values of different members of a given data set ', 178, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO23', 'MATH-G1-DH-ELO3', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Arrange sets of data from greatest to least  ', 179, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO24', 'MATH-G1-DH-ELO3', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Use a variety of strategies (tally charts, matching, counters, array diagrams, bar charts, etc.) to identify the count of each member of given data set. ', 180, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO25', 'MATH-G1-DH-ELO3', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'State reason(s) why identified members in a data set has a low or high frequency.', 181, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO26', 'MATH-G1-DH-ELO3', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Identify and speak about trends in data set presented in tables, pictographs and or concrete bar charts. ', 182, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO27', 'MATH-G1-DH-ELO3', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Represent given data on a tally or graph. ', 183, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO28', 'MATH-G1-DH-ELO3', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Arrange data according to frequency. ', 184, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO29', 'MATH-G1-DH-ELO3', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Order sets of data displayed from greatest to least using tallies, concrete graph and pictographs.  ', 185, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO30', 'MATH-G1-DH-ELO3', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Appreciate the fact that the same data can be represented differently. ', 186, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO31', 'MATH-G1-DH-ELO3', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Speak freely of how different strategies used by students helps in making learning interesting.', 187, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO32', 'MATH-G1-DH-ELO4', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Identify that data can be represented in tally charts, tables, concrete graphs, and pictographs ', 188, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO33', 'MATH-G1-DH-ELO4', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Read and interpret data represented in tables, pictographs and bar charts  ', 189, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO34', 'MATH-G1-DH-ELO4', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Distinguish among the different ways in which data can be represented ', 190, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO35', 'MATH-G1-DH-ELO4', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Read and interpret data presented in various ways. ', 191, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO36', 'MATH-G1-DH-ELO4', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Generate and answer questions based on data presented in tally charts, concrete graphs, pictographs ', 192, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO37', 'MATH-G1-DH-ELO4', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Use correctly vocabulary (most, least, more than, less than, etc.) when speaking about the occurrences of members in a data set', 193, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO38', 'MATH-G1-DH-ELO4', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Draw conclusions based on the analysis of information given. ', 194, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO39', 'MATH-G1-DH-ELO4', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Analyze data to obtain essential information. ', 195, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO40', 'MATH-G1-DH-ELO4', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Interpret information from data presented in graphs, tally charts, tables, concrete charts.  ', 196, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO41', 'MATH-G1-DH-ELO4', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Appreciate the importance of being able to present sets of data  in multiple ways ', 197, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO42', 'MATH-G1-DH-ELO4', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Begin to accept that different students can interpret the same data in different ways. ', 198, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO43', 'MATH-G1-DH-ELO4', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Students make informed decisions based on the information received.', 199, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
