  ('MATH-G1-DH-SCO45', 'MATH-G1-DH-ELO5', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Predict possible outcomes of events given.  ', 201, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('MATH-G1-DH-SCO46', 'MATH-G1-DH-ELO5', 'MATH-G1-DH', 'MATH', 'mathematics', 'G1', '1', 'Data Handling and Probability', 'Make informed decisions based on predictions and outcomes of event. ', 202, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
