  ('LANG-G1-LS-SCO1', 'LANG-G1-LS-ELO1', 'LANG-G1-LS', 'LANG', 'language-arts', 'G1', '1', 'Listening and Speaking', 'Listen and speak for pleasure and personal growth', 204, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO1', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Choose to listen to music, poetry and stories for pleasure. ', 205, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO2', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Connect environmental sounds to meaning. ', 206, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO3', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Use different voices in role playing to indicate tone and mood.  ', 207, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
