  ('LANG-G1-RV-SCO6', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Listen to, retell, and express an opinion about the story.   ', 210, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO7', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Listen to differentiate between make-believe and truth. ', 211, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO8', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Listen to follow and give direction e.g. 2-3 steps. ', 212, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO9', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Listen and respond with increasing understanding  and confidence to conversations expressed in Standard English ', 213, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO10', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Listen and speak to form and foster relationships ', 214, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO11', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Use turn taking strategies as a listener and a speaker.  ', 215, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO12', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Identify and use some non-verbal cues (e.g., facial expressions, gestures etc.) and in oral communication with thoughtfulness. ', 216, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO13', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Listen, share information ask and and answer questions on a topic opinion in response to views articulated by others.  ', 217, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO14', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Listen and speak to develop appreciation and celebration of culture and oral languages. ', 218, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO15', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Use and respond  to Home Language(s) with awareness and purpose to greet, thank, make a request, explain, apologise and issue an invitation.  ', 219, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO16', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Continue to develop Home Language and Standard English vocabulary, phrasing and sentence use to share ideas.  ', 220, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO17', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Describe sounds, images, events, people, and places with clarity that includes: relevant details and a range of descriptive words reflecting size, colour, intensity, etc.  ', 221, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO18', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Produce complete sentences when suitable to task and setting ', 222, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO19', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Continue to develop the foundation of phonological awareness by orally identifying, producing, and manipulating various units of speech sounds within words, including: initial and final sounds - segmenting sounds in one syllable words - beats in a word (syllables) - onset and rhyme - blending sounds to make one-syllable words.  - identifying phonemes in one syllable words ', 223, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO20', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Use common singular and plural nouns in the meaningful context of sentences(e.g. She runs, We run)', 224, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO21', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'begin to use common irregular plural forms, such as man/men, child/children, and foot/feet ', 225, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO22', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'use common pronouns with increasing understanding ( I, me, mine, they, them, theirs, him, his,  hers)', 226, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO23', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'reflect on and connect interests and background knowledge before, during and after reading. ', 227, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO24', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'apply Concepts About Print to navigate Emergent/Early level text. ', 228, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO25', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'connect background knowledge to new learning. ', 229, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO26', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'regard reading/viewing as sources of interest, enjoyment, and information ', 230, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO27', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'engage in reading or reading-like behaviour to experience a variety of text and text forms', 231, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO28', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'participate in opportunities to share favourite texts with peers ', 232, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO29', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 're-read, retell and act out selections of familiar stories, poems, and nonfiction texts ', 233, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO30', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Select and engage critically, with a range of texts for personal growth ', 234, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO31', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'select, with teacher assistance, texts appropriate to their interests and reading progress ', 235, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO32', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'select just right texts with assistance and beginning independence  ', 236, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO33', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'use illustrations in a text to describe and interpret characters, setting, and events ', 237, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO34', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'use nonfiction instructions and text features to create models or artistic representations', 238, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO35', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'formulate questions as well as understandings of digital fiction and nonfiction text, ', 239, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO36', 'LANG-G1-RV-ELO1', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'develop an understanding and respect for diversity in text.', 240, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO37', 'LANG-G1-RV-ELO2', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Share and discuss texts with peers ', 241, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO38', 'LANG-G1-RV-ELO2', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Retell the beginning, middle, and end of stories and events using images, drama, models and written summaries, using  ', 242, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO39', 'LANG-G1-RV-ELO2', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Use illustrations, graphics etc. to ask and answer questions, draw conclusions and make inferences, identify details, synthesise main main idea from the details ', 243, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO40', 'LANG-G1-RV-ELO2', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Use a variety of comprehension strategies to create meaning in poetry, fiction, and nonfiction texts during Independent Reading: •	combine text information with background 
•	knowledge and experiences  
•	create visualisations 
•	predict what will happen 
•	make inferences by drawing on their own experiences and clues in the text 
•	ask and answer questions about representations of character, setting and content 
•	identify basic character traits from text and visual contextual clues and critical reflection, 
•	make connections between texts, noticing similarities in characters, events, illustrations, and language,  
•	identify details from text and images  
•	identify main idea ', 244, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO41', 'LANG-G1-RV-ELO2', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'demonstrate understanding through various responses to text:  •	artistic representations (visual arts, dance, etc.)
•	discussions 
•	graphic organisers 
•	oral and written responses to questions ', 245, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO42', 'LANG-G1-RV-ELO2', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Continue to make connections between Home Language vocabulary and Standard English vocabulary to the language of the story, poem, song, or visual representations, ', 246, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO43', 'LANG-G1-RV-ELO2', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Apply known oral vocabulary within familiar language patterns to make meaning from text, ', 247, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO44', 'LANG-G1-RV-ELO2', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Continue to develop use of context clues to solve unknown vocabulary, ', 248, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO45', 'LANG-G1-RV-ELO2', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Begin to automatically read and understand sight and some highfrequency words and words of personal interests or significance in a variety of reading contexts ', 249, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('LANG-G1-RV-SCO46', 'LANG-G1-RV-ELO2', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Demonstrate understanding (not definitions) and application of synonyms, antonyms, and homophones  ', 250, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO47', 'LANG-G1-RV-ELO2', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Begin to understand how Emergent/Early level prefixes and suffixes change the meaning of words.  ', 251, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO48', 'LANG-G1-RV-ELO2', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Expand vocabulary by noticing and using frequently occurring root words to read inflectional forms (e.g., look, looks, looked, looking) ', 252, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO49', 'LANG-G1-RV-ELO2', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Develop visualisation strategies to connect words, and phrases of Home Language and Standard English text to meaningful mental images ', 253, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO50', 'LANG-G1-RV-ELO2', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Demonstrate understanding of how word order in fiction and nonfiction text impacts meaning,  ', 254, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO51', 'LANG-G1-RV-ELO2', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Begin to apply punctuation(full stop, question mark, exclamation mark) and bold print to guide intonation and expression, change the tone, and for emphasis, etc.  ', 255, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO52', 'LANG-G1-RV-ELO2', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Apply automatic knowledge of known sight words within sentences  to develop phrasing, fluency, and expression ', 256, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO53', 'LANG-G1-RV-ELO2', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', ' Continue to recognise and meaningfully apply Emergent/Early stage knowledge of letter patterns to decode unfamiliar words.  •	initial and some final and medial consonants 
•	Emergent/Early-stage blends 
•	Emergent/Early-stage digraphs
•	Emergent/Early-stage consonant vowel letters ', 257, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO54', 'LANG-G1-RV-ELO2', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Apply knowledge of word order, illustrations, text content and initial, final and some medial letter sounds to identify unknown words,  ', 258, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO55', 'LANG-G1-RV-ELO2', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Begin to monitor for errors by cross checking phonics, meaning, and structure clues.', 259, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO56', 'LANG-G1-RV-ELO3', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Begin to become familiar with the style of local and favourite international  authors (Eric Carle, Dr. Seuss, Robert Munsch, Bill Martin, Dr. Seuss, Richard Scary, Maurice Sendak, etc. ): -does the author write fiction or nonfiction? -is the author humorous or serious? -does the author use a lot of words of just a few words -which are do you enjoy reading or listening to? Why? -does the author use unusual words? - What’s an example?  ', 260, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO57', 'LANG-G1-RV-ELO3', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Engage with and participate in Shared Reading and Readers Theatre in fiction, nonfiction, and poetry to connect reading with personal and audience engagement. ', 261, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO58', 'LANG-G1-RV-ELO3', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Develop an understanding of text features such as bold print and font size adds to an author’s style.  ', 262, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO59', 'LANG-G1-RV-ELO3', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Ask questions of author’s purpose for writing: - Who is the author writing for? - How does the author want you to feel? What does the author want you to know or think about?  ', 263, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO60', 'LANG-G1-RV-ELO3', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Continue to develop understanding and purpose of fiction, nonfiction, and poetry genres as represented by Emergent and Early Stage: Pictures ,Poems ,Stories ,Fantasy stories, Informational texts ', 264, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO61', 'LANG-G1-RV-ELO3', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Apply some text features to locate and predict information in text: title, table of contents, illustrations, labels on diagrams, back blurb, numbered steps', 265, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO62', 'LANG-G1-RV-ELO3', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Read and follow simple  written and/or illustrated instructions ', 266, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO63', 'LANG-G1-RV-ELO3', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Use text features to support individual and/or small group research on topic of interest  ', 267, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO64', 'LANG-G1-RV-ELO3', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Search for answers to questions on digital sites', 268, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO65', 'LANG-G1-RV-ELO3', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Discuss interesting words that evoke emotions ', 269, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO66', 'LANG-G1-RV-ELO3', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Create a personal word bank  ', 270, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO67', 'LANG-G1-RV-ELO3', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Develop an understanding that words may have similar meanings ', 271, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO68', 'LANG-G1-RV-ELO3', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Continue to develop an understanding of how written word order impacts meaning. ', 272, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO69', 'LANG-G1-RV-ELO3', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Compare texts by same illustrator for similarities in mood (happy, funny, exciting, etc.) ', 273, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-RV-SCO70', 'LANG-G1-RV-ELO3', 'LANG-G1-RV', 'LANG', 'language-arts', 'G1', '1', 'Reading and Viewing', 'Explore how emoticons, symbols, and shapes are used to convey or enhance meaning', 274, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO1', 'LANG-G1-WR-ELO1', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Begin to develop strategies for the prewriting stages of the writing process ', 275, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO2', 'LANG-G1-WR-ELO1', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Talk about the ideas they plan to write about; provide learners with prompts that are of interest and relevant ', 276, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO3', 'LANG-G1-WR-ELO1', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Draft some illustrations to accompany ideas and write thoughts that match the ideas in their drawings  ', 277, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO4', 'LANG-G1-WR-ELO1', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Use role play to assist with brainstorming ideas ', 278, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO5', 'LANG-G1-WR-ELO1', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Begin to use simple graphic organizers to brainstorm and plan  ', 279, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO6', 'LANG-G1-WR-ELO1', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Begin to become familiar with the purpose of various genres and how different genres look and sound: narratives,  poetry, expository ', 280, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO7', 'LANG-G1-WR-ELO1', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Begin to develop strategies for the connecting prewriting to the drafting stages of the writing process ', 281, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO8', 'LANG-G1-WR-ELO1', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Write to match text to their brainstorm, planning and drawings ', 282, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO9', 'LANG-G1-WR-ELO1', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Begin to identify the topic, purpose, audience and form for writing ', 283, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO10', 'LANG-G1-WR-ELO1', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Begin to experiment with creating a draft in different forms e.g. poems, invitations, excuses, informal letters  ', 284, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO11', 'LANG-G1-WR-ELO1', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Begin to experiment with writing in simple sentences that may include descriptive words or simple transition words (and, but, then etc.). ', 285, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO12', 'LANG-G1-WR-ELO1', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Begin to organise sentences into paragraphs by writing narratives with two or more appropriately sequenced events and some sense of closure ', 286, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO13', 'LANG-G1-WR-ELO1', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'With assistance, begin to become familiar with the keyboard for individual or shared writing  ', 287, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO14', 'LANG-G1-WR-ELO1', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Work with a partner, in small groups and independently, to create a draft writing in both print and/or digital format  ', 288, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO15', 'LANG-G1-WR-ELO1', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Continue to use role plays to assist with drafting process planning, convey and enhance meaning  ', 289, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO16', 'LANG-G1-WR-ELO1', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Apply lessons learned about writing to record feelings, thoughts and ideas during Independent or Journal writing time. ', 290, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO17', 'LANG-G1-WR-ELO2', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'engage in teacher assisted and peer collaboration to review the organisation of the written draft through the process of ARMS: Add, Remove, Move, Substitute', 291, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO18', 'LANG-G1-WR-ELO2', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'revisit brainstorming and illustration and illustration to add details to and/or delete details.', 292, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO19', 'LANG-G1-WR-ELO2', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Reread their draft and begin to recognize where they can make changes to better organise the beginning, middle, and end; first, second third, etc.', 293, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO20', 'LANG-G1-WR-ELO2', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Experiment with developing writing with a sense of flow  ', 294, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO21', 'LANG-G1-WR-ELO2', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Begin to establish a personal voice in their writing by using pictures and words that convey their attitude or feelings towards the subject or audience ', 295, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO22', 'LANG-G1-WR-ELO2', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Begin to extend writing to include vocabulary learned during reading and conversation ', 296, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO23', 'LANG-G1-WR-ELO2', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Experiment with using multisensory words (hearing, smell), taste, etc.) to improve writing ', 297, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO24', 'LANG-G1-WR-ELO2', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Begin to use comparison words to distinguish one thing from another—size, shape, texture  ', 298, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO25', 'LANG-G1-WR-ELO2', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Become comfortable making decisions about when to include Home Language and/ or Standard English', 299, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('LANG-G1-WR-SCO26', 'LANG-G1-WR-ELO2', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Monitor and revise writing to ensure simple but complete sentences are meaningful ', 300, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO27', 'LANG-G1-WR-ELO2', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Develop more understanding of how and when to use descriptive or action words to extend meaning of draft  ', 301, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO28', 'LANG-G1-WR-ELO2', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'apply knowledge of spoken language to know when to use pronouns, plurals, and words indicating position (above, below, under, etc.)  ', 302, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO29', 'LANG-G1-WR-ELO2', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'experiment with some variety in first sentences (leads) of writing ', 303, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO30', 'LANG-G1-WR-ELO2', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'demonstrate understanding of the connection between word order and meaningful writing ', 304, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO31', 'LANG-G1-WR-ELO2', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Begin to use various types of sentences: declarative, question, and exclamation  ', 305, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO32', 'LANG-G1-WR-ELO2', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Use techniques demonstrated by favorite authors (descriptive words, funny words, short sentences, long sentence, asking questions, etc.) ', 306, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO33', 'LANG-G1-WR-ELO2', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Use expressive language to elaborate and create interest', 307, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO34', 'LANG-G1-WR-ELO3', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Develop increased confidence, and accuracy willingness to try out various strategies (risk taking) to increase spelling and punctuation accuracy, tidiness  and presentation  ', 308, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO35', 'LANG-G1-WR-ELO3', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Write from left to right and from top to bottom consistently  ', 309, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO36', 'LANG-G1-WR-ELO3', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Use some conventional spacing ', 310, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO37', 'LANG-G1-WR-ELO3', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Continue to develop a relaxed hand while writing ', 311, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO38', 'LANG-G1-WR-ELO3', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Attempt to make letter formation readable by various audiences  ', 312, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO39', 'LANG-G1-WR-ELO3', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Monitor and check high frequency words with the aid of: environmental print, word walls, personal dictionaries', 313, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO40', 'LANG-G1-WR-ELO3', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Generate temporary and accurate spelling based on phonological strategies such as: -using words posted on the word wall and/or in an individual word book. - stretching out sounds or use sound boxes.
-developing awareness of sequencing and blending sounds (beginning, middle and ending of a word)
-clapping syllables and spelling each syllable separately.
-thinking about spelling patterns from known or rhyming words.', 314, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO41', 'LANG-G1-WR-ELO3', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Continue to develop spelling of single syllable words by applying knowledge of: -beginning and ending consonants
-two-letter initial consonant blends - beginning and some ending consonant digraphs
-short and long vowel sounds
-knowledge of vowel clusters', 315, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO42', 'LANG-G1-WR-ELO3', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Become increasingly familiar with predictable letter patterns to spell more accurately:  -CVC (consonant, vowel, consonant)
-CVCC (consonant, vowel, consonant, consonant)
-CVVC (consonant, vowel, vowel, consonant)
-CVCE (consonant, vowel, consonant, e)', 316, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO43', 'LANG-G1-WR-ELO3', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Apply letter and word knowledge  strategies during the writing process to monitor (notice errors), edit errors and check for correctness.  ', 317, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO44', 'LANG-G1-WR-ELO3', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Apply sight word knowledge gathered through reading and writing to “try out” different spellings of a word to see which one looks right. ', 318, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO45', 'LANG-G1-WR-ELO3', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Begin to be aware of digital features such as spell check ', 319, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO46', 'LANG-G1-WR-ELO3', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Spell commonly used sight words and phonetically regular words with increasing correctness in final copies ', 320, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO47', 'LANG-G1-WR-ELO3', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Begin to add a few grade-level punctuation conventions: -full stops
-question marks
-exclamation marks
-capitals on names and at the beginning of a sentence.', 321, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO48', 'LANG-G1-WR-ELO3', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Develop hand created or digital presentation styles using various forms of hand or digitally generated: -illustrations
-titles
-fonts', 322, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('LANG-G1-WR-SCO49', 'LANG-G1-WR-ELO3', 'LANG-G1-WR', 'LANG', 'language-arts', 'G1', '1', 'Writing and Representing', 'Participate in opportunities to share (through in person or digital format) a chosen piece of writing with peers or an invited audience  ', 323, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO1', 'SCIENCE-G1-WLS-ELO1', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Define the terms: •	Sounds
•	vibrate
•	waves
•	loud
•	Soft
•	Sign Language', 324, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO2', 'SCIENCE-G1-WLS-ELO1', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Demonstrate an understanding of how to produce sounds.', 325, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO3', 'SCIENCE-G1-WLS-ELO1', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Compare and describe sounds produced as (loud, soft, pleasant, unpleasant.', 326, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO4', 'SCIENCE-G1-WLS-ELO1', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Discuss and identify the effects and uses of sounds in our daily lives.', 327, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO5', 'SCIENCE-G1-WLS-ELO1', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Show that sound is a wave - like water is a wave.', 328, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO6', 'SCIENCE-G1-WLS-ELO1', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Classify - sounds according to loudness.', 329, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO7', 'SCIENCE-G1-WLS-ELO1', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Investigate - how sounds are produced and its effects on objects.', 330, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO8', 'SCIENCE-G1-WLS-ELO1', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Observe - the effects of sounds on objects.', 331, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO9', 'SCIENCE-G1-WLS-ELO1', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Predict the effects of sounds on objects and the sounds made by different materials.', 332, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO10', 'SCIENCE-G1-WLS-ELO1', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Communicate effectively the results of sound experiments.', 333, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO11', 'SCIENCE-G1-WLS-ELO1', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Work respectfully with others in exploring and investigating sounds.', 334, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO12', 'SCIENCE-G1-WLS-ELO1', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Show respect for persons with hearing or speaking impairment.', 335, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO13', 'SCIENCE-G1-WLS-ELO1', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Willingly observe, question, and explore the effects of sounds.', 336, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO14', 'SCIENCE-G1-WLS-ELO1', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Show interest and curiosity about sounds and their uses.', 337, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO15', 'SCIENCE-G1-WLS-ELO1', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Develop an awareness that loud sounds (noise pollution) affect people and animals e.g., loud music, machinery, firecrackers, and airplanes.', 338, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO16', 'SCIENCE-G1-WLS-ELO2', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Define the terms: •	Light/darkness
•	Artificial
•	Natural
•	Reflect', 339, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO17', 'SCIENCE-G1-WLS-ELO2', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Give examples of the sources of light.', 340, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO18', 'SCIENCE-G1-WLS-ELO2', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Identify different light sources in and out of the classroom.', 341, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO19', 'SCIENCE-G1-WLS-ELO2', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Describe why objects can be seen when illuminated. (Based on reflection of light to eyes.', 342, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO20', 'SCIENCE-G1-WLS-ELO2', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Understand that the sun is a natural source of light that is a burning sphere.', 343, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO21', 'SCIENCE-G1-WLS-ELO2', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Understand that the spherical moon reflects the sun’s light.', 344, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO22', 'SCIENCE-G1-WLS-ELO2', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Classify light according to their source (natural, artificial).', 345, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO23', 'SCIENCE-G1-WLS-ELO2', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Investigate - how objects can be seen.', 346, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO24', 'SCIENCE-G1-WLS-ELO2', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Observe - the effects of light on objects.', 347, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO25', 'SCIENCE-G1-WLS-ELO2', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Predict the effects of turning on and off the lights in a room, closing and opening eyes, etc.', 348, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO26', 'SCIENCE-G1-WLS-ELO2', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Communicate ideas about light using new words.', 349, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('SCIENCE-G1-WLS-SCO27', 'SCIENCE-G1-WLS-ELO2', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Safe use of candles as a source of light.', 350, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO28', 'SCIENCE-G1-WLS-ELO2', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Willingly participate in, and contribute to classroom discussions.', 351, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO29', 'SCIENCE-G1-WLS-ELO2', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Develop an awareness that light must be present for objects to be seen.', 352, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO30', 'SCIENCE-G1-WLS-ELO2', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Appreciate the importance of light e.g. for warning (sirens), safety (lighthouse, traffic lights.).', 353, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO31', 'SCIENCE-G1-WLS-ELO2', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Show appreciation for and assist persons with visual impairment.', 354, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO32', 'SCIENCE-G1-WLS-ELO3', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Define the terms: •	Glass
•	Transparent 
•	Translucent
•	Reflective
•	Reflect
•	Opaque', 355, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-WLS-SCO33', 'SCIENCE-G1-WLS-ELO3', 'SCIENCE-G1-WLS', 'SCIENCE', 'science', 'G1', '1', 'Wave, Lights and Sound', 'Demonstrate they understand that objects can block varying amounts of light from passing.', 356, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
