  ('SCIENCE-G1-SFI-SCO7', 'SCIENCE-G1-SFI-ELO1', 'SCIENCE-G1-SFI', 'SCIENCE', 'science', 'G1', '1', 'Structure, Function and Information Processing', 'Give examples of how humans mimic plants and/or animals to solve problems.', 395, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-SFI-SCO8', 'SCIENCE-G1-SFI-ELO1', 'SCIENCE-G1-SFI', 'SCIENCE', 'science', 'G1', '1', 'Structure, Function and Information Processing', 'Identify some human problems that have been solved by mimicking how plants and /or animals use their external parts.', 396, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-SFI-SCO9', 'SCIENCE-G1-SFI-ELO1', 'SCIENCE-G1-SFI', 'SCIENCE', 'science', 'G1', '1', 'Structure, Function and Information Processing', 'Classify some common things as either: living or non-living.', 397, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-SFI-SCO10', 'SCIENCE-G1-SFI-ELO1', 'SCIENCE-G1-SFI', 'SCIENCE', 'science', 'G1', '1', 'Structure, Function and Information Processing', 'Observe examples of how plants and/or animals use their external parts for survival, growth and to meet their needs.', 398, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-SFI-SCO11', 'SCIENCE-G1-SFI-ELO1', 'SCIENCE-G1-SFI', 'SCIENCE', 'science', 'G1', '1', 'Structure, Function and Information Processing', 'Communicate properties of mimicked plants and animals by observing and describing.', 399, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('SCIENCE-G1-SFI-SCO12', 'SCIENCE-G1-SFI-ELO1', 'SCIENCE-G1-SFI', 'SCIENCE', 'science', 'G1', '1', 'Structure, Function and Information Processing', 'Use simple materials to design a solution to a human problem using examples from the external parts of plants and or animals.', 400, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-SFI-SCO13', 'SCIENCE-G1-SFI-ELO1', 'SCIENCE-G1-SFI', 'SCIENCE', 'science', 'G1', '1', 'Structure, Function and Information Processing', 'Construct a simple model of a gadget designed to solve the problem and test its effectiveness.', 401, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-SFI-SCO14', 'SCIENCE-G1-SFI-ELO1', 'SCIENCE-G1-SFI', 'SCIENCE', 'science', 'G1', '1', 'Structure, Function and Information Processing', 'Appreciate that the external parts of plants and animals have inspired technological designs.', 402, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
