  ('SCIENCE-G1-SFI-SCO16', 'SCIENCE-G1-SFI-ELO1', 'SCIENCE-G1-SFI', 'SCIENCE', 'science', 'G1', '1', 'Structure, Function and Information Processing', 'Willingly participate in classroom discussions and group activities with peers.', 404, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
