  ('SCIENCE-G1-SFI-SCO18', 'SCIENCE-G1-SFI-ELO1', 'SCIENCE-G1-SFI', 'SCIENCE', 'science', 'G1', '1', 'Structure, Function and Information Processing', 'Observe all applicable safety measures when interacting with plant/animal specimens or using tools.', 406, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-SFI-SCO19', 'SCIENCE-G1-SFI-ELO1', 'SCIENCE-G1-SFI', 'SCIENCE', 'science', 'G1', '1', 'Structure, Function and Information Processing', 'Display sensitivity and offer assistance to peers who may have physical or learning challenges when conducting practical and group work.', 407, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-SFI-SCO20', 'SCIENCE-G1-SFI-ELO2', 'SCIENCE-G1-SFI', 'SCIENCE', 'science', 'G1', '1', 'Structure, Function and Information Processing', 'Define the terms:  •	Protect
•	Signal
•	Offspring
•	Survive
•	Behaviour
•	Parents
•	Respond', 408, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
