  ('SCIENCE-G1-SFI-SCO27', 'SCIENCE-G1-SFI-ELO2', 'SCIENCE-G1-SFI', 'SCIENCE', 'science', 'G1', '1', 'Structure, Function and Information Processing', 'Interpret sounds and pictures to make judgements about parent/offspring behaviours.', 415, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
