  ('SCIENCE-G1-SFI-SCO30', 'SCIENCE-G1-SFI-ELO2', 'SCIENCE-G1-SFI', 'SCIENCE', 'science', 'G1', '1', 'Structure, Function and Information Processing', 'Show respect for the parents & offspring, observed by treating them with care.', 418, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SCIENCE-G1-SFI-SCO31', 'SCIENCE-G1-SFI-ELO2', 'SCIENCE-G1-SFI', 'SCIENCE', 'science', 'G1', '1', 'Structure, Function and Information Processing', 'While making observations students will show concern for safety.', 419, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
