  ('SS-G1-CP-SCO7', 'SS-G1-CP-ELO3', 'SS-G1-CP', 'SS', 'social-studies', 'G1', '1', 'Civic Particpation', 'K - Identify persons to turn to when they need help  ', 475, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
