  ('SS-G1-ST-SCO8', 'SS-G1-ST-ELO2', 'SS-G1-ST', 'SS', 'social-studies', 'G1', '1', 'Spatial Thinking', 'V - Appreciate that relative location can influence activities that families engage in.', 491, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SS-G1-ST-SCO9', 'SS-G1-ST-ELO3', 'SS-G1-ST', 'SS', 'social-studies', 'G1', '1', 'Spatial Thinking', 'K - Name and illustrate the four cardinal directions.  ', 492, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SS-G1-ST-SCO10', 'SS-G1-ST-ELO3', 'SS-G1-ST', 'SS', 'social-studies', 'G1', '1', 'Spatial Thinking', 'S - Describe the location of your home using cardinal directions in relation to natural and built features in the community.  ', 493, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SS-G1-ST-SCO11', 'SS-G1-ST-ELO3', 'SS-G1-ST', 'SS', 'social-studies', 'G1', '1', 'Spatial Thinking', 'V - Appreciate the value of directions for finding your way from one location to another.  ', 494, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SS-G1-ST-SCO12', 'SS-G1-ST-ELO4', 'SS-G1-ST', 'SS', 'social-studies', 'G1', '1', 'Spatial Thinking', 'K - List the activities that you and your family engage in because of where you live.  ', 495, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SS-G1-ST-SCO13', 'SS-G1-ST-ELO4', 'SS-G1-ST', 'SS', 'social-studies', 'G1', '1', 'Spatial Thinking', 'S - Classify family activities activities as having a positive or negative impact on the neighbourhood. ', 496, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SS-G1-ST-SCO14', 'SS-G1-ST-ELO4', 'SS-G1-ST', 'SS', 'social-studies', 'G1', '1', 'Spatial Thinking', 'V - Recognize that where we live influences how our families live and that the things we do, have an impact on our neighbourhood.      ', 497, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SS-G1-ST-SCO15', 'SS-G1-ST-ELO5', 'SS-G1-ST', 'SS', 'social-studies', 'G1', '1', 'Spatial Thinking', 'K - Identify natural hazards such as hurricanes, tsunamis, volcanic eruptions, earthquakes which may pose a threat to your family because of where you live. ', 498, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SS-G1-ST-SCO16', 'SS-G1-ST-ELO5', 'SS-G1-ST', 'SS', 'social-studies', 'G1', '1', 'Spatial Thinking', 'S - Demonstrate how to follow evacuation procedures in your school. ', 499, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('SS-G1-ST-SCO17', 'SS-G1-ST-ELO5', 'SS-G1-ST', 'SS', 'social-studies', 'G1', '1', 'Spatial Thinking', 'V-Respect the dangers posed by natural disasters.  ', 500, '[]'::jsonb, '2026-02-21T17:24:21.83026+00:00'),
  ('SS-G1-EDM-SCO1', 'SS-G1-EDM-ELO1', 'SS-G1-EDM', 'SS', 'social-studies', 'G1', '1', 'Economic Decision Making', 'K - Identify basic human needs.  ', 501, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SS-G1-EDM-SCO2', 'SS-G1-EDM-ELO1', 'SS-G1-EDM', 'SS', 'social-studies', 'G1', '1', 'Economic Decision Making', 'S - Distinguish between our basic needs and our wants.  ', 502, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SS-G1-EDM-SCO3', 'SS-G1-EDM-ELO1', 'SS-G1-EDM', 'SS', 'social-studies', 'G1', '1', 'Economic Decision Making', 'V - Appreciate the difference between needs and wants.', 503, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SS-G1-EDM-SCO4', 'SS-G1-EDM-ELO2', 'SS-G1-EDM', 'SS', 'social-studies', 'G1', '1', 'Economic Decision Making', 'K - Understand that we meet most of our needs and wants through goods and services. ', 504, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SS-G1-EDM-SCO5', 'SS-G1-EDM-ELO2', 'SS-G1-EDM', 'SS', 'social-studies', 'G1', '1', 'Economic Decision Making', 'S - Categorise our needs and wants as goods or services. ', 505, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SS-G1-EDM-SCO6', 'SS-G1-EDM-ELO2', 'SS-G1-EDM', 'SS', 'social-studies', 'G1', '1', 'Economic Decision Making', 'V - Appreciate that goods and services are necessary to meet our needs and wants.  ', 506, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SS-G1-EDM-SCO7', 'SS-G1-EDM-ELO3', 'SS-G1-EDM', 'SS', 'social-studies', 'G1', '1', 'Economic Decision Making', 'K - Identify things in the environment that we use. ', 507, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SS-G1-EDM-SCO8', 'SS-G1-EDM-ELO3', 'SS-G1-EDM', 'SS', 'social-studies', 'G1', '1', 'Economic Decision Making', 'S - Discuss how we use things in the environment. ', 508, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SS-G1-EDM-SCO9', 'SS-G1-EDM-ELO3', 'SS-G1-EDM', 'SS', 'social-studies', 'G1', '1', 'Economic Decision Making', 'V - Appreciate that the environment can be used to provide our needs and wants.', 509, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SS-G1-EDM-SCO10', 'SS-G1-EDM-ELO4', 'SS-G1-EDM', 'SS', 'social-studies', 'G1', '1', 'Economic Decision Making', 'K - Understand the various forms of transportation in your local environment.  ', 510, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SS-G1-EDM-SCO11', 'SS-G1-EDM-ELO4', 'SS-G1-EDM', 'SS', 'social-studies', 'G1', '1', 'Economic Decision Making', 'S - Distinguish different forms of transportation and their benefits and limitations. ', 511, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SS-G1-EDM-SCO12', 'SS-G1-EDM-ELO4', 'SS-G1-EDM', 'SS', 'social-studies', 'G1', '1', 'Economic Decision Making', 'V - Appreciate the importance of exercising safety around transportation.  ', 512, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO1', 'MATH-G2-NS-ELO1', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Count by 1s, 2s, 5s and 10s, forward and backward, to 100. ', 513, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO2', 'MATH-G2-NS-ELO1', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Say number sequence by 1s, 2s, 5s and 10s, forward and backward, starting from any point, to 100.', 514, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO3', 'MATH-G2-NS-ELO1', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Read, write and represent whole numbers from 1 - 100. ', 515, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO4', 'MATH-G2-NS-ELO1', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Demonstrate different ways of representing numbers from 1 - 100. ', 516, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO5', 'MATH-G2-NS-ELO1', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Skip count orally in 2s, 5s and 10s up to 200.  ', 517, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO6', 'MATH-G2-NS-ELO1', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Use a variety of methods to count and skip count. ', 518, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO7', 'MATH-G2-NS-ELO1', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Volunteer to count/skip count up to a given number of real-life objects found in the classroom.', 519, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO8', 'MATH-G2-NS-ELO2', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Distinguish between odd and even numbers for groups with up to 20 objects.', 520, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO9', 'MATH-G2-NS-ELO2', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Identify equations that express an even number as a sum of two equal addends.', 521, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO10', 'MATH-G2-NS-ELO2', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Write an equation to express an even number as a sum of two numbers of equal value. ', 522, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO11', 'MATH-G2-NS-ELO2', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Willingly participate in activities involving odd and even numbers. ', 523, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO12', 'MATH-G2-NS-ELO3', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Compare and order numbers up to 100 in ascending or descending order.', 524, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO13', 'MATH-G2-NS-ELO3', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Indicate and describe the position of specific numbers in a sequence by using ordinal numbers up to tenth. ', 525, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO14', 'MATH-G2-NS-ELO3', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Identify 2-digit numbers.  ', 526, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO15', 'MATH-G2-NS-ELO3', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', ' Use vocabulary related to comparing numbers (greater than, less than, equal to).  ', 527, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO16', 'MATH-G2-NS-ELO3', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Distinguish among the symbols (< , >, and =) used to compare 2-digit numbers.  ', 528, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO17', 'MATH-G2-NS-ELO3', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Arrange numbers in order of size and give reasons for their arrangement. ', 529, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO18', 'MATH-G2-NS-ELO3', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', ' Use relevant vocabulary to orally compare numbers (greater than, less than, equal to).  ', 530, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO19', 'MATH-G2-NS-ELO3', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Compare pairs of 2-digit numbers using the symbols (<, > and =).', 531, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO20', 'MATH-G2-NS-ELO3', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Show willingness to participate in games and other activities involving comparing numbers. ', 532, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO21', 'MATH-G2-NS-ELO3', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', ' Volunteer to share on how to compare pairs of numbers.  ', 533, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO22', 'MATH-G2-NS-ELO4', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Identify and contrast among the face value, place value, and total value of the digits in any two-digit number.', 534, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO23', 'MATH-G2-NS-ELO4', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Represent numbers concretely, pictorially and symbolically (expanded notation) up to ninety-nine (99) as groups of tens and ones. ', 535, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO24', 'MATH-G2-NS-ELO4', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Write the place value and total value of any digit in a 2-digit number. ', 536, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO25', 'MATH-G2-NS-ELO4', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Round two-digit numbers to the nearest 10', 537, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO26', 'MATH-G2-NS-ELO4', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Willingly participate in games and other activities involving face value, place value, and total value of digits in 2-digit numbers. ', 538, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO27', 'MATH-G2-NS-ELO4', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Appreciate the importance of knowing the place value and total value of digits.  ', 539, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO28', 'MATH-G2-NS-ELO5', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Recognize simple fractions as representation of the parts of a whole.', 540, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO29', 'MATH-G2-NS-ELO5', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Identify unit fractions correctly. ', 541, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO30', 'MATH-G2-NS-ELO5', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Distinguish between the numerator and the denominator.  ', 542, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO31', 'MATH-G2-NS-ELO5', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Partition given shapes into parts with equal sections.   ', 543, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO32', 'MATH-G2-NS-ELO5', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Shade parts of given shapes to represent named unit fractions up to eighths. ', 544, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO33', 'MATH-G2-NS-ELO5', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Willingly collaborate with classmates in activities involving identifying fractions.', 545, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO34', 'MATH-G2-NS-ELO5', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Choose to explain the use of fractions in their everyday lives.', 546, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO35', 'MATH-G2-NS-ELO6', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Read and write the fractions ½ and ¼ correctly as ‘one half’ and ‘one quarter’ (Not ‘one over two’ and ‘one over four’). ', 547, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO36', 'MATH-G2-NS-ELO6', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Compare two fractions with the same denominator (limited to halves and quarters) referring to the same whole. Order fractions with the same denominator (halves and quarters). ', 548, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-NS-SCO37', 'MATH-G2-NS-ELO6', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Express ways they use fractions on a daily basis. ', 549, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('MATH-G2-NS-SCO38', 'MATH-G2-NS-ELO6', 'MATH-G2-NS', 'MATH', 'mathematics', 'G2', '2', 'Number Sense', 'Show enthusiasm dividing items in fractions to share with a friend. ', 550, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO1', 'MATH-G2-ON-ELO1', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Add up to three two-digit numbers within 100 using a variety of strategies without and with regrouping. ', 551, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO2', 'MATH-G2-ON-ELO1', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Subtract two-digit number from two-digit number using a variety of strategies without and with regrouping. ', 552, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO3', 'MATH-G2-ON-ELO1', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Mentally demonstrate their ability to add 10’s or 100’s up to 900 from a given number. ', 553, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO4', 'MATH-G2-ON-ELO1', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Identify that addition is the opposite of subtraction. ', 554, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO5', 'MATH-G2-ON-ELO1', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Use appropriate vocabulary to explain addition and subtraction strategies. ', 555, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO6', 'MATH-G2-ON-ELO1', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Use a variety of strategies and tools to add and subtract two-digit numbers with and without regrouping.  ', 556, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO7', 'MATH-G2-ON-ELO1', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Use problem solving strategies for up to two step problem involving addition and subtraction using single digits. ', 557, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO8', 'MATH-G2-ON-ELO1', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'List occasions when they have to add or subtract. ', 558, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO9', 'MATH-G2-ON-ELO1', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Appreciate the importance of knowing how to add and subtract in everyday life.', 559, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO10', 'MATH-G2-ON-ELO2', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Use addition to find the total number of objects arranged in rectangular arrays with up to 5 rows and up to 5 columns.', 560, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO11', 'MATH-G2-ON-ELO2', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Write an equation to express total as a sum of equal addends.', 561, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO12', 'MATH-G2-ON-ELO2', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Demonstrate initial multiplication and division knowledge related to sharing, grouping and array. ', 562, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO13', 'MATH-G2-ON-ELO2', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', ' Show how multiplication undo division and vice versa. ', 563, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO14', 'MATH-G2-ON-ELO2', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Finding a missing quantity given the whole and another known quantity. ', 564, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO15', 'MATH-G2-ON-ELO2', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Identify times in their daily lives where they would have to use the multiplication strategy or identify totals using array.', 565, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO16', 'MATH-G2-ON-ELO3', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Interpret repeated addition procedures, using terms such as ‘sets of’, ‘times’, ‘groups of.', 566, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO17', 'MATH-G2-ON-ELO3', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Use mathematical language such as ‘4 threes’ and ‘2 groups of 5’ to describe equal groups.', 567, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO18', 'MATH-G2-ON-ELO3', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Demonstrate their understanding of the word multiplication and division by correctly solving problems.', 568, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO19', 'MATH-G2-ON-ELO3', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Write a number sentence for a given situation involving multiplication or division.', 569, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO20', 'MATH-G2-ON-ELO3', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Solve a 1-step picture problem involving multiplication and division.', 570, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO21', 'MATH-G2-ON-ELO3', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Work out a multiplication fact by repeated addition.', 571, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO22', 'MATH-G2-ON-ELO3', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Make a number story for a given multiplication or division sentence.', 572, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO23', 'MATH-G2-ON-ELO3', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Demonstrate the ability to share objects equally in groups or sets.', 573, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-ON-SCO24', 'MATH-G2-ON-ELO3', 'MATH-G2-ON', 'MATH', 'mathematics', 'G2', '2', 'Operations with Numbers', 'Work cooperatively to place manipulatives in groups to demonstrate repeated addition.', 574, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO1', 'MATH-G2-PR-ELO1', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Describe a given pattern.', 575, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO2', 'MATH-G2-PR-ELO1', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Identify whether given terms form a pattern or not.', 576, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO3', 'MATH-G2-PR-ELO1', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Make predictions as to what may come next in a given pattern. ', 577, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO4', 'MATH-G2-PR-ELO1', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Create and extend simple patterns with 3-5 elements. ', 578, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO5', 'MATH-G2-PR-ELO1', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Create patterns resulting from repeating an operation or making a repeated change to an attribute. ', 579, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO6', 'MATH-G2-PR-ELO1', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Copy and extend a repeating pattern (using manipulatives, diagrams, body movements/actions/sounds) ', 580, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO7', 'MATH-G2-PR-ELO1', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', ' Translate simple repeating patterns (E.g., a repeating orientation pattern to a repeating sound pattern, etc.).  ', 581, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO8', 'MATH-G2-PR-ELO1', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Copy and extend growing patterns.  ', 582, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO9', 'MATH-G2-PR-ELO1', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Recognize patterns as either repeating or growing.  ', 583, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO10', 'MATH-G2-PR-ELO1', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Acknowledge patterns in their environment by identifying and describing the pattern observed around them. ', 584, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO11', 'MATH-G2-PR-ELO1', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Identify and enjoy patterns in poems, stories, (folk and modern) within their culture.  ', 585, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO12', 'MATH-G2-PR-ELO2', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Determine the rule used to extend a growing and a shrinking pattern.  ', 586, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO13', 'MATH-G2-PR-ELO2', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Identify, describe, and create through investigation, growing and shrinking patterns (increasing and decreasing) involving addition and subtraction. ', 587, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO14', 'MATH-G2-PR-ELO2', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Solve simple patterns involving increasing and decreasing patterns. ', 588, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO15', 'MATH-G2-PR-ELO2', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Use pattern rules to extend patterns and to make predictions. ', 589, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO16', 'MATH-G2-PR-ELO2', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Complete patterns where elements are missing. ', 590, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO17', 'MATH-G2-PR-ELO2', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Demonstrate the ability to obtain a rule for a number pattern by determining the relationship between given numbers. ', 591, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO18', 'MATH-G2-PR-ELO3', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Identify and interpret simple number sentences using words, diagrams and symbols. ', 592, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO19', 'MATH-G2-PR-ELO3', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Communicate and interpret simple additive and subtractive strategies using words, diagrams and symbols.  ', 593, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO20', 'MATH-G2-PR-ELO3', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Explain how the arrangement of numbers (commutative property) does not affect the sum/total. ', 594, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO21', 'MATH-G2-PR-ELO3', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Recognize that the commutative property does not apply to subtraction. ', 595, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO22', 'MATH-G2-PR-ELO3', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Represent algebraic expressions using variables and symbols. ', 596, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO23', 'MATH-G2-PR-ELO3', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Represent unknown quantities concretely, pictorially and   numerically. ', 597, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO24', 'MATH-G2-PR-ELO3', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Simplify algebraic expression problems involving an unknown quantity in an addition and subtraction situation. ', 598, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO25', 'MATH-G2-PR-ELO3', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Demonstrate an appreciation for the use of symbols as a substitute for real life objects when counting and grouping items up to a hundred.  ', 599, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('MATH-G2-PR-SCO26', 'MATH-G2-PR-ELO4', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Represent numbers up to 100 in a variety of ways.', 600, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO27', 'MATH-G2-PR-ELO4', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Apply the commutative property when add numbers.', 601, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO28', 'MATH-G2-PR-ELO4', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Identify equivalent monetary values of coins and bills.', 602, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO29', 'MATH-G2-PR-ELO4', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Create equivalent sum of money using different coins. ', 603, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO30', 'MATH-G2-PR-ELO4', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Generalize whole numbers can be decomposed and composed without changing its value.', 604, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO31', 'MATH-G2-PR-ELO5', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Demonstrate and explain what equality means using manipulatives and diagrams (0-100).', 605, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO32', 'MATH-G2-PR-ELO5', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Record equalities and inequalities symbolically using the correct symbol', 606, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO33', 'MATH-G2-PR-ELO5', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Solve for missing quantities to make the equation equivalent.  ', 607, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO34', 'MATH-G2-PR-ELO5', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Model equalities using a variety of concrete representation and record. ', 608, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO35', 'MATH-G2-PR-ELO5', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', ' Appreciate the need for equating an expression to  values. ', 609, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-PR-SCO36', 'MATH-G2-PR-ELO5', 'MATH-G2-PR', 'MATH', 'mathematics', 'G2', '2', 'Patterns and Relationships', 'Accept that an equation is a number sentence.', 610, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO1', 'MATH-G2-GT-ELO1', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Describe orally and written, 2-D and 3-D shapes and/or objects and space.', 611, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO2', 'MATH-G2-GT-ELO1', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Identify 2-D and 3-D shapes in the environment.', 612, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO3', 'MATH-G2-GT-ELO1', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Explain the differences and similarities between and among 2-D shapes using vocabulary associated with properties of shapes.', 613, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO4', 'MATH-G2-GT-ELO1', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Make comparisons between solids and plane shapes in concrete and pictorial forms using formal language.', 614, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO5', 'MATH-G2-GT-ELO1', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Identify 2-D shapes as faces of 3-D shapes in pictures, objects or space from different orientations.', 615, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO6', 'MATH-G2-GT-ELO1', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Classify shapes according to their properties/features and give reasons for the classification.', 616, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO7', 'MATH-G2-GT-ELO1', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Create/build 2-D and 3-D shapes.', 617, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO8', 'MATH-G2-GT-ELO1', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Describe 2-D and 3-D shapes found in the natural environment or in pictures.', 618, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO9', 'MATH-G2-GT-ELO1', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Create 3D shapes using 2D shapes from a description given within a real world context.', 619, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO10', 'MATH-G2-GT-ELO1', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Show an awareness of the properties of 2-D and 3-D shapes in the environment through explorations of multimedia games, toys, props, puzzles, worksheets and songs.', 620, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO11', 'MATH-G2-GT-ELO1', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Investigate and reason about the results of transforming 2-D shapes using the appropriate vocabulary (flipping, turning).', 621, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO12', 'MATH-G2-GT-ELO1', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Identify and describe the position of 2-D and 3-D shapes in relation to another shape, object or space.', 622, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO13', 'MATH-G2-GT-ELO2', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Identify 2D shapes on 3D objects. ', 623, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO14', 'MATH-G2-GT-ELO2', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', ' Represent and construct 2D shapes and 3D objects. ', 624, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO15', 'MATH-G2-GT-ELO2', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', ' Sort 2D shapes and 3D objects based on their attributes and characteristics. ', 625, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO16', 'MATH-G2-GT-ELO2', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', ' Sole repeating patterns using/involving 2D shapes and 3D objects. ', 626, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO17', 'MATH-G2-GT-ELO2', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Create repeating patterns using/ involving 2D shapes and 3D objects. ', 627, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO18', 'MATH-G2-GT-ELO2', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Build composite shapes/structures of 2D and 3D shapes and describe the pattern used. ', 628, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO19', 'MATH-G2-GT-ELO2', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Choose to use 2D shapes to create 3D models using pictorial and physical representations. ', 629, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO20', 'MATH-G2-GT-ELO3', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Identify properties of 2D shapes.  ', 630, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO21', 'MATH-G2-GT-ELO3', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Justify classification of 2D shapes according to attributes.  ', 631, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO22', 'MATH-G2-GT-ELO3', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Identify similarities and differences between 2D shapes based on attributes such as sides or corners. ', 632, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO23', 'MATH-G2-GT-ELO3', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Identify similarities and differences between 3D objects based on attributes such as sides, edges, rolls/slides, uniform thickness or not. ', 633, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO24', 'MATH-G2-GT-ELO3', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Classify 2D shapes as polygons or non-polygons. ', 634, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO25', 'MATH-G2-GT-ELO3', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Compare 2-D shapes in the environment. ', 635, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO26', 'MATH-G2-GT-ELO3', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Differentiate between polygons and non-polygons in the environment. ', 636, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO27', 'MATH-G2-GT-ELO3', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Show an awareness of the existence of 2D shapes by discussing where they are found in everyday life. ', 637, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO28', 'MATH-G2-GT-ELO4', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Identify 3D shapes in the environment based on the attributes of faces, vertices, and edges.', 638, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO29', 'MATH-G2-GT-ELO4', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Classify 3D shapes as prisms and pyramids based on its bases and lateral faces.', 639, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO30', 'MATH-G2-GT-ELO4', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Classify 3D shapes in the environment based on the attributes of sides and corners, circular appearances. ', 640, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO31', 'MATH-G2-GT-ELO4', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Examine various 3D shapes to identify the number of vertices, edges, and faces.  ', 641, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO32', 'MATH-G2-GT-ELO4', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Acknowledge the importance of 3D and 2D shapes in the creation of various objects in the environment.  ', 642, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO33', 'MATH-G2-GT-ELO5', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Compare shapes and objects (2D & 3D) on the basis of attributes using appropriate vocabulary. ', 643, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO34', 'MATH-G2-GT-ELO5', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Describe the relative location/position of 2D shapes and 3D objects in relation to other shapes and objects (above/below, over/under, beside/inside/outside, to the right/left of behind/in front of). ', 644, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO35', 'MATH-G2-GT-ELO5', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Describe the movements required to place an object in a particular position, relative to another object (left/right, up/down).', 645, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO36', 'MATH-G2-GT-ELO5', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Use a variety of models, materials to create shapes. ', 646, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO37', 'MATH-G2-GT-ELO5', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Volunteer to identify objects in the environment that are in various shapes.  ', 647, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO38', 'MATH-G2-GT-ELO6', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Duplicate composite 2D and 3D shapes that are presented. ', 648, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO39', 'MATH-G2-GT-ELO6', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Design composite 2D representations combining the faces of more than one 2D shape. ', 649, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('MATH-G2-GT-SCO40', 'MATH-G2-GT-ELO6', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Create composite 3D structures using 3D objects in their environment. ', 650, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO41', 'MATH-G2-GT-ELO6', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Make composite representations of 2D and 3D shapes using technology.            ', 651, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO42', 'MATH-G2-GT-ELO6', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Solve problems involving 2D and 3D shapes. ', 652, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO43', 'MATH-G2-GT-ELO6', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Justify the use of the shapes used to create their composite 2D and 3D shapes stating the properties of the shapes that make them suitable.', 653, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO44', 'MATH-G2-GT-ELO7', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Identify 2D shapes that are part of the composition of 3D objects using footprints, making shadows, or slicing.   ', 654, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO45', 'MATH-G2-GT-ELO7', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Deconstruct 3D objects to identify the 2D shapes that constitute their formation through slicing, making shadows and footprints. ', 655, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO46', 'MATH-G2-GT-ELO7', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Volunteer to conduct a presentation on 2D shapes in the composition of 3D objects.', 656, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO47', 'MATH-G2-GT-ELO8', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Students will be expected to accurately transform 2D and 3D shapes by rotating them flipping them', 657, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO48', 'MATH-G2-GT-ELO8', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Students will be able to accurately differentiate between a flip and a rotation ', 658, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-GT-SCO49', 'MATH-G2-GT-ELO8', 'MATH-G2-GT', 'MATH', 'mathematics', 'G2', '2', 'Geometrical Thinking', 'Volunteer to justify why a shape has been flipped or rotated.', 659, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO1', 'MATH-G2-M-ELO1', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Explain in your own words the concept of linear measurement.', 660, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO2', 'MATH-G2-M-ELO1', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Differentiate among measurable attributes related to linear measurements (length, width, height, depth and distance).', 661, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO3', 'MATH-G2-M-ELO1', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Use vocabulary relating to each attribute (long, short, wide, narrow, deep, shallow, far, tall, near).', 662, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO4', 'MATH-G2-M-ELO1', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Describe the term of nonstandard units.', 663, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO5', 'MATH-G2-M-ELO1', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Use non-standard units (units must be the same size and must be joined from end to end - no gaps)', 664, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO6', 'MATH-G2-M-ELO1', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Compare and order measurements using nonstandard units of measurement.', 665, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO7', 'MATH-G2-M-ELO1', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Choose to use standard and non-standard units for the measurement of linear measurement where appropriate.', 666, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO8', 'MATH-G2-M-ELO2', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Estimate and measure length, height, and distance, using standard units (i.e. centimetre, metre).', 667, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO9', 'MATH-G2-M-ELO2', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Record and represent measurements of height, and distance length using a variety of ways (e.g. concretely, pictorial, written). ', 668, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO10', 'MATH-G2-M-ELO2', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Use a measuring tool such as a ruler or a tape measure, in both centimetres and metres to measure length, height and distances. ', 669, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO11', 'MATH-G2-M-ELO2', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Identify the starting point of a measuring tool. ', 670, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO12', 'MATH-G2-M-ELO2', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Recognize and use the abbreviations "cm" and "m" when measuring and recording lengths. ', 671, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO13', 'MATH-G2-M-ELO2', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Create real life scenarios that involve measuring lengths, height and distances.', 672, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO14', 'MATH-G2-M-ELO3', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Identify the appropriate unit of time such as seconds, minutes, hours, days etc. to describe a given activity or event.', 673, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO15', 'MATH-G2-M-ELO4', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Create a time log of a daily activity using a specified unit(s) of time. ', 674, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO16', 'MATH-G2-M-ELO4', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Compare the time taken to complete two or more given activities using nonstandard units. (number of claps, number of jumps, number of steps it takes to complete some thing). ', 675, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO13', 'MATH-G2-DH-ELO3', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Analyze data and make informed decisions using these data. ', 714, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO17', 'MATH-G2-M-ELO4', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Use seconds, minutes, and hours to measure and describe the duration of various events. ', 676, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO18', 'MATH-G2-M-ELO4', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Compare and order the durations of different events using terms such as shorter, longer, and equal. ', 677, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO19', 'MATH-G2-M-ELO4', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Solve simple addition and subtraction problems involving duration of time. ', 678, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO20', 'MATH-G2-M-ELO4', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'use appropriate vocabulary to describe time such as "seconds,", "minutes," "hours," "shorter," "longer," "earlier," and "later," among others.', 679, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO21', 'MATH-G2-M-ELO5', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Use units of time, including seconds, minutes, hours, and non-standard units, to describe the duration of various events. ', 680, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO22', 'MATH-G2-M-ELO5', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Represent and read time on the hour, half past the hour and quarter past the hour. ', 681, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO23', 'MATH-G2-M-ELO5', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Tell time from analog and digital clocks to the nearest five minutes, using a.m. and p.m.', 682, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO24', 'MATH-G2-M-ELO5', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Add a mixed collection of coins whose sum is less than or equal to one dollar. e.g. 25c, 10c and 5c pieces. ', 683, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO25', 'MATH-G2-M-ELO5', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Solve real world and mathematical problems within one dollar involving 25c, 10c, 5c, and pennies, using the ¢ (cent) symbol appropriately.', 684, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO26', 'MATH-G2-M-ELO6', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Compare Measurement of lengths using a standard unit. ', 685, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO27', 'MATH-G2-M-ELO6', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Solve addition and subtraction problems involving lengths up to 100 that are given in the same units. ', 686, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO28', 'MATH-G2-M-ELO6', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Estimate lengths using centimeters and Meters. ', 687, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO29', 'MATH-G2-M-ELO6', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Explore and estimate liquid volumes and masses of objects using standard units of grams (g) and milliliters (ml). ', 688, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO30', 'MATH-G2-M-ELO6', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Measure attributes like length, weight, and time accurately by using units such as inches, centimeters, pounds, kilograms, and minutes. ', 689, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO31', 'MATH-G2-M-ELO6', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Estimate measurements and make comparisons between different objects or quantities based on their attributes such as longer/shorter, heavier/lighter, and faster/slower. ', 690, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO32', 'MATH-G2-M-ELO6', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Use measurement tools such as rulers, scales, and timers to measure and compare attributes.  ', 691, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO33', 'MATH-G2-M-ELO6', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Use simple formulas related to measurement to calculate the perimeter of basic shapes or find the average length of objects.', 692, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO34', 'MATH-G2-M-ELO7', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Identify the standard units of grams (g) for mass and milliliters (mL) for volume. ', 693, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO35', 'MATH-G2-M-ELO7', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Estimate the volume of liquid in containers using milliliters (mL) as the unit of measurement. ', 694, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO36', 'MATH-G2-M-ELO7', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Estimate the mass of objects using grams (g) as the unit of measurement. ', 695, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO37', 'MATH-G2-M-ELO7', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Compare and order different volumes of liquids and masses of objects using concepts such as more than, less than, and equal to when comparing volumes and masses. ', 696, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO38', 'MATH-G2-M-ELO7', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Use measuring tools, such as graduated cylinders or measuring cups, to measure the volume of liquids accurately in milliliters (mL). ', 697, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO39', 'MATH-G2-M-ELO7', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Use a balance or scale to measure the mass of objects accurately in grams (g).', 698, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('MATH-G2-M-SCO40', 'MATH-G2-M-ELO7', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Record measurements of volumes and masses in appropriate units (grams or milliliters) and write them in numerical form. ', 699, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO41', 'MATH-G2-M-ELO7', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Solve problems involving estimating and measuring volumes and masses using grams and milliliters. ', 700, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-M-SCO42', 'MATH-G2-M-ELO7', 'MATH-G2-M', 'MATH', 'mathematics', 'G2', '2', 'Measurement', 'Create real-life situations, such as measuring ingredients for a recipe or estimating the amount of liquid in a container.', 701, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO1', 'MATH-G2-DH-ELO1', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Identify simple topics of collective interest for investigation.  ', 702, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO2', 'MATH-G2-DH-ELO1', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Match investigative topics to relevant questions.', 703, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO3', 'MATH-G2-DH-ELO1', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Formulate questions that can be answered by gathering information about self, others, and their environment.', 704, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO4', 'MATH-G2-DH-ELO1', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Appreciate the need for the use of appropriate questions in data collection.', 705, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO5', 'MATH-G2-DH-ELO2', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'List questions of interest for investigation.', 706, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO6', 'MATH-G2-DH-ELO2', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Gather and record simple sets of data about self and others through observation and simple interviews.', 707, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO7', 'MATH-G2-DH-ELO2', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Record data as a tally or as drawings (pictographs). ', 708, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO8', 'MATH-G2-DH-ELO2', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Use collected data to answer questions. ', 709, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO9', 'MATH-G2-DH-ELO2', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Make the connection that data collection is acquiring information to answer important questions.', 710, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO10', 'MATH-G2-DH-ELO3', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Identify the most frequent count presented in any data sets (e.g., concrete graphs, pictographs, bar graphs, and tables).', 711, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO11', 'MATH-G2-DH-ELO3', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Explain in their own words what the most frequent count indicates about the data. ', 712, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO14', 'MATH-G2-DH-ELO3', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Use data to make informed decisions about real life situations. ', 715, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO15', 'MATH-G2-DH-ELO3', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Appreciate the importance of identifying the most frequent count of any given data.', 716, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO16', 'MATH-G2-DH-ELO4', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Ask questions to collect data. ', 717, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO17', 'MATH-G2-DH-ELO4', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Collect simple sets of data through observation and simple interview. ', 718, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO18', 'MATH-G2-DH-ELO4', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Use number statements to record the collected data. ', 719, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO19', 'MATH-G2-DH-ELO4', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Collect data using a variety of observation tools. ', 720, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO20', 'MATH-G2-DH-ELO4', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Organize, display and communicate data that has been collected. ', 721, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO21', 'MATH-G2-DH-ELO4', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Record data information on, bar graph, pictograph and tally chart. ', 722, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO22', 'MATH-G2-DH-ELO4', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Create different types of data presentations, including pictograph, and bar graphs to represent data. ', 723, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO23', 'MATH-G2-DH-ELO4', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Identify the most frequent count, if any, for various data sets presented in concrete graphs, pictographs, bar graphs, and tables. Identify the key elements of pictograph and bar graph. ', 724, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO24', 'MATH-G2-DH-ELO4', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Analyze data presented in various ways by asking and answering questions about the data. ', 725, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO25', 'MATH-G2-DH-ELO4', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Draw conclusions from the data by making observations and inferences.', 726, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO26', 'MATH-G2-DH-ELO5', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Students should be able to: ', 727, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO27', 'MATH-G2-DH-ELO5', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Describe the likelihood that events will happen and use that information to make predictions.', 728, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO28', 'MATH-G2-DH-ELO5', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Use mathematical language, including the terms “impossible”, “possible”, and “certain”, to describe the likelihood of complementary events happening. ', 729, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('MATH-G2-DH-SCO29', 'MATH-G2-DH-ELO5', 'MATH-G2-DH', 'MATH', 'mathematics', 'G2', '2', 'Data Handling ', 'Use the likelihood that an event will happen to make predictions and informed decisions.', 730, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-LS-SCO1', 'LANG-G2-LS-ELO1', 'LANG-G2-LS', 'LANG', 'language-arts', 'G2', '2', 'Listening and Speaking', 'Engage with various genres of music, oral poetry, and oral stories for pleasure. ', 731, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-LS-SCO2', 'LANG-G2-LS-ELO1', 'LANG-G2-LS', 'LANG', 'language-arts', 'G2', '2', 'Listening and Speaking', 'Offer thoughts and opinions on the meaning and mood of music, stories, and poetry. ', 732, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-LS-SCO3', 'LANG-G2-LS-ELO1', 'LANG-G2-LS', 'LANG', 'language-arts', 'G2', '2', 'Listening and Speaking', 'Sustain one-to-one conversations and contribute to small and large group interactions with peers.  ', 733, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-LS-SCO4', 'LANG-G2-LS-ELO1', 'LANG-G2-LS', 'LANG', 'language-arts', 'G2', '2', 'Listening and Speaking', 'Continue to develop comfort while engaging in interactions with adults. ', 734, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-LS-SCO5', 'LANG-G2-LS-ELO1', 'LANG-G2-LS', 'LANG', 'language-arts', 'G2', '2', 'Listening and Speaking', 'Describe a personal experience in sequential order. ', 735, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-LS-SCO6', 'LANG-G2-LS-ELO1', 'LANG-G2-LS', 'LANG', 'language-arts', 'G2', '2', 'Listening and Speaking', 'Continue to develop vocabulary that reflects interests as well as application of synonyms, antonyms, and descriptive words to build more complex sentences.  ', 736, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-LS-SCO7', 'LANG-G2-LS-ELO1', 'LANG-G2-LS', 'LANG', 'language-arts', 'G2', '2', 'Listening and Speaking', 'Use some transition words to connect phrases. ', 737, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-LS-SCO8', 'LANG-G2-LS-ELO1', 'LANG-G2-LS', 'LANG', 'language-arts', 'G2', '2', 'Listening and Speaking', 'Respond to and give instructions that involve 3-4 steps. ', 738, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-LS-SCO9', 'LANG-G2-LS-ELO1', 'LANG-G2-LS', 'LANG', 'language-arts', 'G2', '2', 'Listening and Speaking', 'Demonstrate application of oral comprehension strategies such as: •	visualising 
•	predicting 
•	connecting 
•	analysis 
•	synthesising 
•	determining importance ', 739, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-LS-SCO10', 'LANG-G2-LS-ELO1', 'LANG-G2-LS', 'LANG', 'language-arts', 'G2', '2', 'Listening and Speaking', 'Describe, share, and discuss thoughts, feelings, and experiences.  ', 740, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-LS-SCO11', 'LANG-G2-LS-ELO1', 'LANG-G2-LS', 'LANG', 'language-arts', 'G2', '2', 'Listening and Speaking', 'Ask and respond to questions to clarify information and to explore possibilities or solutions to problems.  ', 741, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-LS-SCO12', 'LANG-G2-LS-ELO1', 'LANG-G2-LS', 'LANG', 'language-arts', 'G2', '2', 'Listening and Speaking', 'Consider others’ ideas and ask/ respond to questions to clarify information and to explore possibilities or solutions to problems. ', 742, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-LS-SCO13', 'LANG-G2-LS-ELO1', 'LANG-G2-LS', 'LANG', 'language-arts', 'G2', '2', 'Listening and Speaking', 'Recognize some examples of unfair and hurtful vocabulary and begin to make vocabulary choices that affirm rather than hurt people. ', 743, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-LS-SCO14', 'LANG-G2-LS-ELO1', 'LANG-G2-LS', 'LANG', 'language-arts', 'G2', '2', 'Listening and Speaking', 'Experiment with the impact of intonation, expression, and tone while communicating ideas and feelings in small- and whole group situations.  ', 744, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-LS-SCO15', 'LANG-G2-LS-ELO1', 'LANG-G2-LS', 'LANG', 'language-arts', 'G2', '2', 'Listening and Speaking', 'Begin to make vocabulary choices that affirm sensitivity to the personal ideas, cultural contexts, and experiences of others.  ', 745, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-LS-SCO16', 'LANG-G2-LS-ELO1', 'LANG-G2-LS', 'LANG', 'language-arts', 'G2', '2', 'Listening and Speaking', 'Use social conventions, in range of conversations and cooperative play situations, (turn taking, politeness, when to speak, and when to listen) in multiple cultural contexts.  ', 746, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-LS-SCO17', 'LANG-G2-LS-ELO1', 'LANG-G2-LS', 'LANG', 'language-arts', 'G2', '2', 'Listening and Speaking', 'Use different forms (Home Language, Standard English) of language dependent upon audience and purpose. ', 747, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-LS-SCO18', 'LANG-G2-LS-ELO1', 'LANG-G2-LS', 'LANG', 'language-arts', 'G2', '2', 'Listening and Speaking', 'Recognize that volume of voice needs to be adjusted according to situation.  ', 748, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-LS-SCO19', 'LANG-G2-LS-ELO1', 'LANG-G2-LS', 'LANG', 'language-arts', 'G2', '2', 'Listening and Speaking', 'Continue to develop monitoring and self correction of oral language use. ', 749, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO32', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Create and use a personal word bank.  ', 782, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('LANG-G2-LS-SCO20', 'LANG-G2-LS-ELO1', 'LANG-G2-LS', 'LANG', 'language-arts', 'G2', '2', 'Listening and Speaking', 'Develop automaticity with the meaningful application of phonological awareness in oral expression of : •	rhyming 
•	onset and rime 
•	segmenting 
•	blending 
•	beats in a word (syllables)  ', 750, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO1', 'LANG-G2-RV-ELO1', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Continue to make engaging and ‘just right’ book choices for Independent Reading based on:
•	interests 
•	various cultures (theirs and others) 
•	difficulty level 
•	genre ', 751, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO2', 'LANG-G2-RV-ELO1', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Reflect on various sources of background knowledge to predict and make connections before, during and after reading a piece of: 
•	fiction 
•	nonfiction 
•	poetry ', 752, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO3', 'LANG-G2-RV-ELO1', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Increase time (build stamina) while engaged in Independent Reading', 753, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO4', 'LANG-G2-RV-ELO1', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Engage critically with a range of texts for pleasure. ', 754, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO5', 'LANG-G2-RV-ELO1', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Regard reading/viewing as sources of interest, enjoyment, and information.', 755, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO6', 'LANG-G2-RV-ELO1', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Share ideas and opinions about favourite authors or favourite genres with peers. ', 756, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO7', 'LANG-G2-RV-ELO1', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Make meaningful personal, text and community/world connections that enhance comprehension. ', 757, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO8', 'LANG-G2-RV-ELO1', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Select and engage critically with a range of texts for personal growth. ', 758, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO9', 'LANG-G2-RV-ELO1', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Ask critical questions of fiction, nonfiction and poetry (Why, what if, is it possible, etc.) ', 759, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO10', 'LANG-G2-RV-ELO1', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Make connections between wellbeing and information texts on topics such as: 
•	physical activity 
•	health 
•	emotions', 760, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO11', 'LANG-G2-RV-ELO1', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Recognize different points of view of the author of print and/or digital text.', 761, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO12', 'LANG-G2-RV-ELO1', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Continue to develop an understanding and respect for diversity in text and illustrations. ', 762, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO13', 'LANG-G2-RV-ELO1', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Use illustrations and details in a text to describe and interpret characters, setting, and events. ', 763, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO14', 'LANG-G2-RV-ELO1', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Reflect on the purpose of different types of texts e.g., local newspaper articles, local stories, poems, ads, e-texts, etc. ', 764, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO15', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Recognise the purpose and basic similarities and differences in paper based and digital genres of: 
•	fiction   
•	nonfiction 
•	poetry  ', 765, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO16', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Apply a variety of comprehension strategies to create meaning 
•	activating background 
•	knowledge 
•	determining importance 
•	visualisation  
•	prediction  
•	inferring  
•	synthesising  
•	analysing  
•	questions 
•	make connections  ', 766, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO17', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Use illustrations, graphics etc. of nonfiction text to ask questions, make inferences,  and search for answers.  ', 767, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO18', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Use various tools to retell a narrative, referring to characters, problem (what happened), and solution (ending). ', 768, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO19', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Read simple mathematics or science problems to: 
•	search for information 
•	ask questions 
•	find solutions ', 769, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO20', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Demonstrate understanding through various responses to text, such as:  
•	artistic representations (visual arts, dance)  
•	discussions 
•	graphic organisers 
•	oral and written responses to questions · etc.  ', 770, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO21', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Follow written instructions to create an object, find a location, etc. ', 771, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO22', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Begin to connect background knowledge re: community and culture to support  comprehension of culturally relevant text  ', 772, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO23', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Respond critically to texts by asking and formulating responses to questions such as:  
•	what if 
•	is it possible that . . .  
•	what else 
•	what was the author trying to tell us 
•	do I agree/why   ', 773, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO24', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Respond to text focussed on diverse cultures/ways of life with interest, respectful questions and thought.   ', 774, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO25', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Continue to develop use of context (meaning, illustrations, text features, etc.)clues to solve unknown vocabulary.  ', 775, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO26', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Self check on the basis of what makes sense in the text. ', 776, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO27', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Refer to personal dictionaries and published dictionaries as a reference for new vocabulary. ', 777, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO28', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Continue to make connections between the language of text written with Home Language vocabulary and Standard English vocabulary.  ', 778, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO29', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Apply known oral vocabulary to text vocabulary by recognising root words or rimes to solve unknown words. ', 779, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO30', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Continue to develop automaticity with additional high-frequency words and words of personal interest.  ', 780, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO31', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Begin to understand the meaning of Early level prefixes and suffixes. ', 781, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO33', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Develop an understanding that words may have similar meanings. ', 783, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO34', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Continue to notice and apply knowledge of how word order creates and maintains meaning. ', 784, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO35', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Use punctuation  appropriately to: 
•	enhance fluency  
•	guide intonation  
•	demonstrate expression  ', 785, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO36', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Further develop fluency by using knowledge of:
•	effective problem solving of unknown words  
•	predictable language structures ', 786, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO37', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Use fluency to assist:  
•	comprehension 
•	the mood of the text 
•	the intent of the text ', 787, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO38', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Become more aware how the phrases and sentences of text language may be used to describe in positive or negative ways. ', 788, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO39', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Continue to demonstrate understanding of how word order in fiction and nonfiction text impacts meaning. ', 789, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO40', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Make connections between common, simple basic digital text vocabulary and meaning. ', 790, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO41', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Interact with and meaningfully apply Emergent/Early graphophonic cues to a variety of genres and text forms.  ', 791, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO42', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Begin to monitor for errors by cross checking phonics, meaning, and structure clues.', 792, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO43', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Use picture cues to support /enhance graphophonic word solving.  ', 793, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO44', 'LANG-G2-RV-ELO2', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Continue to develop meaningful use of graphophonic elements to decode meaningfully such as:  -initial, final, and medial consonants 
•	Early-stage blends 
•	Early-stage digraphs 
•	Early-stage consonant vowel patterns 
•	simple affixes and visible root words ', 794, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO45', 'LANG-G2-RV-ELO3', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Become familiar with the style of favourite authors and illustrators. ', 795, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO46', 'LANG-G2-RV-ELO3', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Use the work of a range of authors to compare and contrast purpose and style: 
•	humorous stories 
•	exciting stories ', 796, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO47', 'LANG-G2-RV-ELO3', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Work with a peer to begin digital searches to gather information about an author.    ', 797, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO48', 'LANG-G2-RV-ELO3', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Become familiar with the text feature design choices of the author and publishers 
•	front and back cover illustrations 
•	back blurb information 
•	choice of words to enhance interest 
•	use of local and international culture ', 798, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO49', 'LANG-G2-RV-ELO3', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Engage in the research process with teacher and peer assistance:
•	generate questions to guide research 
•	locate appropriate information with assistance (classroom, library, home, community)  
•	organise information (see ELO 6) 
•	share information ', 799, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO50', 'LANG-G2-RV-ELO3', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Express opinions about the work of authors and illustrators. ', 800, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('LANG-G2-RV-SCO51', 'LANG-G2-RV-ELO3', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Discuss and respond to the author''s use of interesting words and dialogue that evoke emotions, describe, create humour, etc. ', 801, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO52', 'LANG-G2-RV-ELO3', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Continue to develop an understanding of how written word order impacts meaning. ', 802, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-RV-SCO53', 'LANG-G2-RV-ELO3', 'LANG-G2-RV', 'LANG', 'language-arts', 'G2', '2', 'Reading and Viewing', 'Compare texts by different authors for differences in language and mood.', 803, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO1', 'LANG-G2-WR-ELO1', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Engage in writing and representing activities every day and sustain engagement in writing.', 804, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO2', 'LANG-G2-WR-ELO1', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Continue to engage in conversations about:
•	why we write or draw
•	how we write or draw
•	how authors use words and sentences to share their ideas
•	how illustrators provide additional information to the writing
•	how authors use choices about when to use Home Language and when to use Standard English', 805, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO3', 'LANG-G2-WR-ELO1', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Develop comfort in experimenting within different forms of formal and informal writing, such as:
•	simple handwritten or digital notes
•	thank you notes
•	invitations to school or class
•	letters to peers or community members', 806, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO4', 'LANG-G2-WR-ELO1', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Engage in conversations about an anchor text chosen to model the genre for the writing project.  ', 807, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO5', 'LANG-G2-WR-ELO1', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Participate in large group and small group opportunities to brainstorm ideas about a topic or a writing prompt. ', 808, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO6', 'LANG-G2-WR-ELO1', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Use simple graphic organizers, such as pictures, the five-finger plan, web, list, five Ws, etc.  to organize ideas into a draft.  ', 809, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO7', 'LANG-G2-WR-ELO1', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Organise brainstormed ideas through increasingly independent use of: 
•	a print, visual or digital graphic organizer 
•	group conversation 
•	story boards  
•	role play 
•	text based models ', 810, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO8', 'LANG-G2-WR-ELO1', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Organize writing to match the genre being studied:  
•	narrative writing 
•	expository writing 
•	descriptive writing
•	persuasive writing ', 811, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO9', 'LANG-G2-WR-ELO1', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Make decisions about when illustrations, charts, and alternate language use will enhance the writing.       ', 812, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-ES-SCO5', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Describe formation in simple terms.', 1072, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('LANG-G2-WR-SCO10', 'LANG-G2-WR-ELO1', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Understand that writing a draft is connected to the prewriting/brainstorming and organising process. ', 813, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO11', 'LANG-G2-WR-ELO1', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Approach draft writing from a positive perspective of taking risks by: 
•	using temporary spelling 
•	exploring various languages 
•	writing freely with a 
•	focus on getting ideas on 
•	paper or device  ', 814, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO12', 'LANG-G2-WR-ELO1', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Refer to anchor texts as examples of the genre of the writing project. ', 815, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO13', 'LANG-G2-WR-ELO1', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Continue to work with a partner, small group or independently, to begin the process of drafting ', 816, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO14', 'LANG-G2-WR-ELO1', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Further develop the structure of the genre throughout the draft process of: 
•	narrative writing 
•	expository writing 
•	descriptive writing 
•	persuasive writing ', 817, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO15', 'LANG-G2-WR-ELO1', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Continue to develop understanding of the social aspect of writing by engaging with peers and the teacher for ideas, suggestions, and ongoing feedback.  ', 818, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO16', 'LANG-G2-WR-ELO2', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Identify different forms of print and digital writing that are appropriate to specific purposes and audiences.', 819, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO17', 'LANG-G2-WR-ELO2', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Review the draft and monitor writing for form and organisation using revision tools such as:
•	inserting a word by using a caret,
•	crossing out a word
•	adding /removing details
•	using arrows to indicate how ideas can be better organised', 820, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO18', 'LANG-G2-WR-ELO2', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Add details or labels to a picture with thought and purpose.', 821, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO19', 'LANG-G2-WR-ELO2', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Focus revisions on creating print, visual and digital texts with a beginning, middle, and end', 822, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO20', 'LANG-G2-WR-ELO2', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Experiment with organisation with various real-world genres: wish list, how to list, grocery list, etc.', 823, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO21', 'LANG-G2-WR-ELO2', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Continue to notice and make choices about the use of Standard English or Home Language vocabulary to enhance word choice.', 824, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO22', 'LANG-G2-WR-ELO2', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Become aware of how to make decisions about word specific choice to enhance clarity:
•	use concrete nouns,
•	use accurate verbs,
•	use a variety of meaningful descriptive words.', 825, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO23', 'LANG-G2-WR-ELO2', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Continue to develop and refine the intentional and meaningful use of Home Language and Standard English vocabulary:
•	transition words, such as first, next, then, after, finally, etc.
•	attribute words—colour, size, shape, texture multisensory words—hearing, smell
•	comparison words of size, shape, texture  ', 826, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO24', 'LANG-G2-WR-ELO2', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Use the word wall to check for alternates for overused words  ', 827, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO25', 'LANG-G2-WR-ELO2', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Experiment with lead sentences that will engage the audience. ', 828, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO26', 'LANG-G2-WR-ELO2', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Begin to embed  structures for plurals and simple past tense in sentence.', 829, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO27', 'LANG-G2-WR-ELO2', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Use expressive Home Language and or Standard English phrases and vocabulary, as appropriate to the topic, to enhance message.', 830, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO28', 'LANG-G2-WR-ELO2', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Experiment with how an author uses bold print, visual words, and fonts to enhance author’s voice. ', 831, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO29', 'LANG-G2-WR-ELO2', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Develop an understanding of how to write complete sentences on a specific topic.', 832, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO30', 'LANG-G2-WR-ELO2', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Begin to experiment with and use revising strategies to develop sentence fluency of:
•	Statements,
•	Questions,
•	Exclamations,
•	Short sentences,
•	Longer sentences.', 833, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO31', 'LANG-G2-WR-ELO2', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Experiment with lead sentences that will engage the audience.', 834, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO32', 'LANG-G2-WR-ELO2', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Begin to embed structures for plurals and simple past tense in sentences. ', 835, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO33', 'LANG-G2-WR-ELO2', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Use expressive Home Language and Standard English words and phrases to enhance the message. ', 836, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO34', 'LANG-G2-WR-ELO2', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Experiment with how an author uses bold print, visual words, and fonts to enhance the author’s voice.', 837, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO35', 'LANG-G2-WR-ELO3', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Continue to develop independent strategies to monitor and edit spelling and make corrections with increasing independence. ', 838, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO36', 'LANG-G2-WR-ELO3', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Use an increasing number of accurately spelled words.', 839, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO37', 'LANG-G2-WR-ELO3', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Use word walls, personal dictionaries, environmental print to check and/or confirm commonly used words. ', 840, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO38', 'LANG-G2-WR-ELO3', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Generate spelling of unfamiliar words based on: 
•	the beginning, middle, and ending sounds in words,  
•	continue to develop accuracy with a short vowel in each syllable of a word,  
•	blending sounds and syllables to make a word,  
•	use an increasing number of letters to represent sound.', 841, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO39', 'LANG-G2-WR-ELO3', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Demonstrate increasing knowledge of more complex spelling patterns, including long vowel patterns (ai, ay, oa, ou, ee, ea).  ', 842, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-ES-SCO116', 'SCIENCE-G2-ES-ELO4', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Label a diagram of the water cycle.', 1183, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('LANG-G2-WR-SCO40', 'LANG-G2-WR-ELO3', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Continue to develop understanding of how to sequence letters when spelling unfamiliar words.  ', 843, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO41', 'LANG-G2-WR-ELO3', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Demonstrate the knowledge of an increasing number of accurately spelt  words. ', 844, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO42', 'LANG-G2-WR-ELO3', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Apply a wider range of spelling strategies resulting in more conventional or close to conventional spelling. ', 845, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO43', 'LANG-G2-WR-ELO3', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Continue to develop the use of digital features such as spell check. ', 846, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO44', 'LANG-G2-WR-ELO3', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Continue to refine the use of grade-level punctuation conventions: 
•	full stops,
•	question marks, 
•	exclamation marks, 
•	capitals on names, I, dates, and beginning of a sentence, 
•	use lower-case letters within words,  
•	begin to use commas in a series. ', 847, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO45', 'LANG-G2-WR-ELO3', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Demonstrate a beginning awareness of when to use quotation marks.', 848, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('LANG-G2-WR-SCO46', 'LANG-G2-WR-ELO3', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Make final corrections of revised draft. ', 849, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO47', 'LANG-G2-WR-ELO3', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Self-select final pieces of writing to publish that demonstrate grade-level traits and conventions. ', 850, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO48', 'LANG-G2-WR-ELO3', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Use conventional spacing between words.  ', 851, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO49', 'LANG-G2-WR-ELO3', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Continue to refine letter formation to increase readability by various audiences.   ', 852, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO50', 'LANG-G2-WR-ELO3', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Develop hand-created or digital presentation styles: 
•	illustrations 
•	titles 
•	charts 
•	emoticons
•	simple maps
•	etc.  ', 853, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO51', 'LANG-G2-WR-ELO3', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Share writing and other representations with others and seek response. ', 854, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO52', 'LANG-G2-WR-ELO3', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'With assistance, experiment with technology in writing and other forms of representing: 
•	using a tape recorder to record, 
•	choral readings, 
•	dramatizations, 
•	retellings of finished pieces of writing. ', 855, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO53', 'LANG-G2-WR-ELO3', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Create illustrations/ drawings with a computer graphics/drawing program. ', 856, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('LANG-G2-WR-SCO54', 'LANG-G2-WR-ELO3', 'LANG-G2-WR', 'LANG', 'language-arts', 'G2', '2', 'Writing and Representing', 'Compose simple text (and begin to revise and edit) with a word processing program.', 857, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO1', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Define the terms:
•	Matter
•	Characteristics
•	Properties
•	Solid
•	Liquid
•	Gas
•	Materials
•	Properties
•	Texture
•	Hard/Soft
•	Flexible
•	Elastic
•	Rigid
•	Natural materials
•	Living
•	Manmade materials', 858, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO2', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'State that matter is composed of particles.', 859, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO3', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Demonstrate they understand the properties of the states of matter.', 860, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO4', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Demonstrate they understand the properties of the different types of materials (metal, paper, wood, plastic, fabric, etc).', 861, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO5', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Compare solids, liquids and gases based on their properties.', 862, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO6', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Distinguish between an object and the material it is made from.', 863, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO7', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Determine the properties to be observed in the investigations.', 864, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO8', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Distinguish between objects and the materials from which they are made (ST-2PS-MM-1).', 865, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO9', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Identify different materials such as wood, rubber, metal, plastic and list objects made from each (ST-2-PS-MM-2).', 866, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO10', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Describe giving examples, the properties of solids and liquids (ST-2-PS-MM-5).', 867, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO11', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Identify examples of at least two solids and two liquids (ST-2-PS-MM-6).', 868, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO12', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Realise that some things are natural and some are human made (ST-2-TE-NT-1).', 869, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO13', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'List some physical properties of matter (ST-3-PS-MM-1).', 870, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO14', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Match, with relevant examples, properties of materials which make them useful for specific purposes (ST-3-PS-MM-4).', 871, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO15', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Observe the three states of matter', 872, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO16', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Identify the three states of matter and give examples of each.', 873, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO17', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Observe different types of materials', 874, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO18', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Identify the properties of different materials.', 875, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO19', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Compare different types of materials based on their observable properties.', 876, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO20', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Compare solids, liquids and gases based on their properties.', 877, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO21', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Classify matter as solids, liquids and gases.', 878, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO22', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Classify materials based on observable properties.', 879, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO23', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Classify objects based on the materials they are made from.', 880, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO24', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Communicate the results from the various investigations to the class and teacher.', 881, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO25', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Plan investigations to describe and classify different kinds of materials.', 882, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO26', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Conduct investigations to classify materials by their observable properties.', 883, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO27', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Collect and analyse data gathered after observing different materials.', 884, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO28', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Collect and analyse data gathered after observing each state of matter.', 885, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO29', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Analyze and interpret data obtained from their observations to classify matter and materials.', 886, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO30', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Investigate the properties of various materials and match the properties to their use (ST-2-PS-MM-3).', 887, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO31', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Develop curiosity by finding out about objects and materials around them.', 888, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO32', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Appreciate that materials have similar and different properties.', 889, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO33', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Develop inquiry through investigating materials and their properties.', 890, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO34', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Show respect for evidence by using the results from the investigations to make classifications.', 891, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO35', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Safety when conducting practical and group work, display sensitivity and offer assistance to peers who may have physical or learning challenges.', 892, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO36', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Participate actively in classroom discussions.', 893, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO37', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Show persistence in completing practical activities, especially those that may be challenging.', 894, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO38', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Work collaboratively, cooperatively and respectfully with other members of their group in exploring and investigating different materials. ', 895, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO39', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Show sensitivity and demonstrate helpfulness when working with peers that may have learning or physical challenges as you undertake experimental work together.', 896, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO40', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Stewardship/Respect for Living Things:
•	Take care not to damage objects (living and nonliving things) when they are making observations about materials in the environment.
•	Use materials wisely.', 897, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO41', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Safety:
•	Wear safety goggles when conducting certain experiments.
•	Be careful not to taste materials unless told to do so by the teacher. o Use safety protocols for collecting objects.
•	Wash hands after conducting certain activities, especially when playing with soil or materials collected outside the classroom. ', 898, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('SCIENCE-G2-SPM-SCO42', 'SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Realise that some things are natural and some are human made (ST-2-TE-NT-1).', 899, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO43', 'SCIENCE-G2-SPM-ELO2', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Give examples of how different materials (e.g. wood, cloth, plastics, clay, metal, etc) are commonly used.', 900, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO44', 'SCIENCE-G2-SPM-ELO2', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Explain why certain materials are more suitable for specific purposes than others.', 901, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO45', 'SCIENCE-G2-SPM-ELO2', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Demonstrate they understand the importance of testing different materials.', 902, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO46', 'SCIENCE-G2-SPM-ELO2', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Compare the properties of different materials to determine suitability for intended purpose.', 903, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO47', 'SCIENCE-G2-SPM-ELO2', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Account for the results obtained from the different tests.', 904, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO48', 'SCIENCE-G2-SPM-ELO2', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'State which properties of a material allow that material to be well suited for an intended use. Use data to suggest reasons for the choice of material.', 905, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO49', 'SCIENCE-G2-SPM-ELO2', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Investigate the properties of various materials and match the properties to the uses (ST-2-PS-MM-3).', 906, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO50', 'SCIENCE-G2-SPM-ELO2', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Design and construct a simple object using chosen materials (ST-2PS-MM-4).', 907, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
  ('SCIENCE-G2-SPM-SCO51', 'SCIENCE-G2-SPM-ELO2', 'SCIENCE-G2-SPM', 'SCIENCE', 'science', 'G2', '2', 'Structure and Properties of Matter', 'Appreciate the advantages and disadvantages of using devices, tools and structures made by humans (ST-2-TE-UT-1). ', 908, '[]'::jsonb, '2026-02-21T17:24:22.324977+00:00'),
