  ('SCIENCE-G2-IRE-SCO37', 'SCIENCE-G2-IRE-ELO1', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Show respect for living things by caring plants around.', 1030, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO38', 'SCIENCE-G2-IRE-ELO1', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Display sensitivity and offer assistance to peers who may have physical or learning challenges when conducting practical and group work.', 1031, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO39', 'SCIENCE-G2-IRE-ELO1', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Participate actively in classroom discussions.', 1032, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO40', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Define the terms: 
•	Dispersal: (in plants) moving seeds around.
•	Pollination: to give (a plant) pollen from another plant of the same kind so that seeds will be produced.
•	Structure: (seeds) the different parts of a seed. Each part has a different function (job). (flower) the different parts of a flower. Each part has a different function.
•	Function: the particular job or purpose of something.
•	Diversity: being different or having a variety of something.
•	Habitat: The place where living things naturally live and grow.
•	Environment: Everything around us; our surroundings. This includes the living and nonliving things around us (air, soil, water, plants, animals).
•	Evaporation: Water changing from the liquid to the gas state.
•	Silt
•	Loam
•	Sand
•	Clay
•	Chalk
•	Invasive species', 1033, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO41', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Discuss how those fruit trees grow. How can seeds make new plants other than placing it in the soil?', 1034, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO42', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Compare the different forms of seed dispersal by animals. (videos, real life).', 1035, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO43', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Show your finished model that mimics the functions of an animal in dispersing seeds or pollinating plants.', 1036, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO44', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Explain simply: seed dispersal.', 1037, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO4', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Describe an earthquake as a natural occurrence and explain what causes it, (ST-5-LS-ECS-15)*', 1071, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO45', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Demonstrate they understand that there are different forms of seed dispersal by animals.', 1038, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO46', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Identify the parts of the flower that aid in pollination (petals, stamen, pistil, pollen).', 1039, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO47', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Give general characteristics of soil types.', 1040, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO48', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Account for how invasive plant species might impact habitat.', 1041, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO49', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Identify the role of each part of a flower and compare the external parts of different flowers (ST-2LS-SF-2).', 1042, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO50', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Define propagation of a seed (ST-3-LS-DC-2).', 1043, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO51', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Outline two natural methods of propagation in flowering plants, giving local examples (ST-3-LSDC-4).', 1044, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO52', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Describe and explain methods of vegetative propagation (ST-3-LS-DC-5).', 1045, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO53', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Identify and describe use of seeds as a means of reproducing different plants (ST-3-LS-DC-6).', 1046, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('SCIENCE-G2-IRE-SCO54', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Identify and describe the various agents of pollination-wind water, animals etc (ST-5-LS-DC-5).', 1047, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO55', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Observe different habitats and record the types of animals and plants that live there.', 1048, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO56', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Infer how animals and plants within different habitats are adapted for seed dispersal and pollination.', 1049, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO57', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Classify seeds based on the type of dispersal (wind, animal, water).', 1050, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO58', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Collect data from videos (using a table) on how seeds are dispersed in the environment.', 1051, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO59', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Communicate their findings about seed dispersal and pollination using oral presentations, tables and charts.', 1052, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO60', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Construct a design for a model to show dispersal of seeds by animals.', 1053, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO61', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Calculate the number of seeds. dispersed by animals, wind and water.', 1054, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO62', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Construct a pictograph using the information gathered.', 1055, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO63', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Interpret data presented in pictographs and charts.', 1056, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO64', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Conduct an experiment to determine how much water is absorbed by different types of soil.', 1057, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO65', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Appreciate the importance of seed dispersal for the survival of plants.', 1058, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO66', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Create solutions to mitigate the impacts of invasive species of plants.', 1059, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO67', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Recognise the role of animals in the survival of different plant species through seed dispersal.', 1060, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO68', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Inquiry into soil absorption gives information for farming', 1061, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO69', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Inventiveness - Create a model to show how animals disperse seeds.', 1062, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO70', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Collaboration & Cooperation - Work collaboratively with their peers to create a model for the type of dispersal selected.', 1063, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO71', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Stewardship/Respect for Living Things.', 1064, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO72', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Safety as the soil experiment is undertaken.', 1065, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO73', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Display sensitivity and offer assistance to peers who may have physical or learning challenges when conducting practical and group work.', 1066, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-IRE-SCO74', 'SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'SCIENCE', 'science', 'G2', '2', 'Interdependent Releationships in Ecosystems', 'Participate actively in classroom discussions.', 1067, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO1', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Define the following terms:
•	Volcano
•	Lava
•	Soil
•	Erupt and eruption o Earth Events
•	Quake
•	Earthquake
•	Erosion', 1068, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO2', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Using examples, demonstrate an understanding of the difference between fast and slow earth events.', 1069, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO3', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Define the term soil erosion, listing types of soil erosion, and ways and means of preventing it (ST5-ESS-ER-1).', 1070, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO6', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Identify volcanic activity as a natural process and explain how volcanoes are formed, as well as the impact on the environment. (ST-5-LS-ECS16) *describe formation in simple terms.', 1073, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO7', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Use new vocabulary to describe your observations.', 1074, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO8', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Draw pictures that demonstrate you understand features of a volcano.', 1075, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO9', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Compare and contrast slow and fast earth events.', 1076, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO10', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Problem solve around preparation to be safe for predictable events.', 1077, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO11', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Interpret video information and pictures.', 1078, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO12', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Communicate ideas about observation of erosion.', 1079, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO13', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'With the assistance of the teacher, construct models.', 1080, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO14', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Appreciate the role of natural processes in shaping the earth.', 1081, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO15', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Compassion for those experiencing hardship due to a dangerous earth event. If able, assist those that have been victims of an earth event. ', 1082, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO16', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Persistence at completing tasks and activities.', 1083, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO17', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Interest/Curiosity- Find out more about different naturally occurring events and objects on their own.', 1084, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO18', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Respect for Evidence - Explain and listen to other students’ results and explanation.', 1085, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO19', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Collaboration & Cooperation- Share ideas with others.', 1086, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO20', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Stewardship/Respect for Living Things- Show sensitivity to living things in the environment.', 1087, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO21', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Apply safety practices during fast earth events such as earthquakes, hurricanes, etc.', 1088, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO22', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'When conducting practical and group work, display sensitivity and offer assistance to peers who may have physical or learning challenges.', 1089, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO23', 'SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Participate actively in classroom discussions.', 1090, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO24', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Define the terms: 
•	Weathering
•	Erosion
•	Livestock
•	Graze
•	Diverting
•	Retaining Wall
•	Roots
•	Crops
•	Windbreaks', 1091, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO25', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Demonstrate they understand that water and wind can change the shape of the land.', 1092, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO26', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Distinguish between weathering and erosion.', 1093, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO27', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Compare ways to prevent wind/water from changing land shape.', 1094, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO28', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Explain at least two given solutions to slow down or prevent wind or water from changing the shape of the land.', 1095, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO29', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Distinguish between water and wind erosion.', 1096, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO30', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Investigate the effects of wave action on the environment (ST-4-LSECS-10).', 1097, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO31', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Plan and execute appropriate research using technological methodology to solve environmental challenges (ST-4-TE-TM-1).', 1098, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('SCIENCE-G2-ES-SCO32', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Observe that the processes of weathering and erosion take a long time but we can readily see their long-term effects.', 1099, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO33', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Classify a process as either weathering or erosion.', 1100, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO34', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Devise a solution to a problem of weathering/erosion based on careful observation of historical pictures.', 1101, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO35', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Hypothesize how diversion of water can be an effective erosion deterrent.', 1102, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO36', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Hypothesize how retention walls can be an effective erosion deterrent.', 1103, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO37', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Hypothesize how placing plants on hillsides can be an effective erosion deterrent.', 1104, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO38', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Hypothesize how adding windbreaks to a field can protect crops.', 1105, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO39', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Communicate to peers the rationale behind models that explain weathering/erosion problem solutions.', 1106, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO40', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Construct a model to explain weathering/erosion control.', 1107, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO41', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Analyse information (field trip, interviews, pictures) from the community in order to formulate problem solutions.', 1108, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO42', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Interpret video to better understand the slow process of weathering/erosion.', 1109, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO43', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Investigate the effects of wave action on the environment (ST-4-LSECS-10).', 1110, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
