  ('SCIENCE-G2-ES-SCO48', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Work diligently to interpret pictures and videos for the information they offer.', 1115, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO49', 'SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Contribute solutions to identified issues of water and wind erosion.', 1116, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
