  ('SCIENCE-G2-ES-SCO59', 'SCIENCE-G2-ES-ELO3', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Identify the 7 continents that make up the earth’s land masses.', 1126, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
