  ('SCIENCE-G2-ES-SCO63', 'SCIENCE-G2-ES-ELO3', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Give three examples of how technology has resulted in water pollution (oil spill, fertilizer, industrial effluent).', 1130, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
  ('SCIENCE-G2-ES-SCO64', 'SCIENCE-G2-ES-ELO3', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'List 5 examples of land pollution.', 1131, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
