  ('SCIENCE-G2-ES-SCO86', 'SCIENCE-G2-ES-ELO3', 'SCIENCE-G2-ES', 'SCIENCE', 'science', 'G2', '2', 'Earth Systems', 'Demonstrate Stewardship/Respect for living things that may be affected by lack of clean water.', 1153, '[]'::jsonb, '2026-02-21T17:24:22.85096+00:00'),
